            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error deleting room", it)
            }
    }

    private fun loadRooms(houseId: String?) {
        if (houseId.isNullOrBlank()) {
            roomList.clear()
            applyRoomFilter()
            return
        }
        Firebase.firestore.collection("rooms")
            .whereEqualTo("houseId", houseId)
            .get()
            .addOnSuccessListener { result ->
                roomList.clear()
                for (document in result) {
                    val room = document.toObject<Room>()
                    room.id = document.id
                    roomList.add(room)
                }
                applyRoomFilter()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error reading rooms", it)
                applyRoomFilter()
            }
    }

    private fun applyRoomFilter() {
        val q = roomSearchQuery.lowercase()
        val oldSize = filteredRooms.size
        filteredRooms.clear()
        ui.lstRooms.adapter?.notifyItemRangeRemoved(0, oldSize)
        if (q.isBlank()) {
            filteredRooms.addAll(roomList)
        } else {
            filteredRooms.addAll(roomList.filter { it.name.orEmpty().lowercase().contains(q) })
        }
        ui.lstRooms.adapter?.notifyItemRangeInserted(0, filteredRooms.size)
        ui.lblRoomCount.text = getString(R.string.room_count_format, filteredRooms.size)
    }

    class RoomHolder(var ui: MyListItemBinding) : RecyclerView.ViewHolder(ui.root)

    class RoomAdapter(
        private val rooms: MutableList<Room>,
        private val onClick: (Int) -> Unit,
        private val onEdit: (Int) -> Unit,
        private val onDelete: (Int) -> Unit,
        private val onLongPress: (Int) -> Unit
    ) : RecyclerView.Adapter<RecyclerView.ViewHolder>() {

        private var isExpanded: Boolean = false
        private var onToggleExpand: (() -> Unit)? = null

        private val ITEM_TYPE_ROOM = 0
        private val ITEM_TYPE_MORE = 1
        private val ITEMS_PER_PAGE = 2

        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): RecyclerView.ViewHolder {
            return if (viewType == ITEM_TYPE_ROOM) {
                val ui = MyListItemBinding.inflate(LayoutInflater.from(parent.context), parent, false)
                RoomHolder(ui)
            } else {
                val button = android.widget.Button(parent.context)
                button.text = parent.context.getString(R.string.show_more_rooms)
                button.setOnClickListener { onToggleExpand?.invoke() }
                val params = ViewGroup.LayoutParams(
                    ViewGroup.LayoutParams.MATCH_PARENT,
                    ViewGroup.LayoutParams.WRAP_CONTENT
                )
                button.layoutParams = params
                MoreHolder(button)
            }
        }

        override fun getItemCount(): Int {
            val visibleCount = if (isExpanded) rooms.size else minOf(ITEMS_PER_PAGE, rooms.size)
            val hasToggle = rooms.size > ITEMS_PER_PAGE
            return visibleCount + (if (hasToggle) 1 else 0)
        }

        override fun getItemViewType(position: Int): Int {
            val visibleCount = if (isExpanded) rooms.size else minOf(ITEMS_PER_PAGE, rooms.size)
            return if (position < visibleCount) ITEM_TYPE_ROOM else ITEM_TYPE_MORE
        }

        override fun onBindViewHolder(holder: RecyclerView.ViewHolder, position: Int) {
            if (holder is RoomHolder && position < rooms.size) {
                val room = rooms[position]
                holder.ui.txtName.text = room.name ?: holder.ui.root.context.getString(R.string.unnamed_room)
                holder.ui.txtYear.text = holder.ui.root.context.getString(R.string.label_room)

                // Load and display room photo
                if (!room.photoBase64.isNullOrBlank()) {
                    try {
                        val bytes = Base64.decode(room.photoBase64, Base64.DEFAULT)
                        val bitmap = BitmapFactory.decodeByteArray(bytes, 0, bytes.size)
                        if (bitmap != null) {
                            holder.ui.imgRoomPhoto.setImageBitmap(bitmap)
                            holder.ui.imgRoomPhoto.visibility = View.VISIBLE
                        } else {
                            holder.ui.imgRoomPhoto.visibility = View.GONE
                        }
                    } catch (e: Exception) {
                        Log.e(FIREBASE_TAG, "Error decoding room photo", e)
                        holder.ui.imgRoomPhoto.visibility = View.GONE
                    }
                } else {
                    holder.ui.imgRoomPhoto.visibility = View.GONE
                }

                holder.ui.root.setOnClickListener {
                    val p = holder.bindingAdapterPosition
                    if (p != RecyclerView.NO_POSITION && p < rooms.size) onClick(p)
                }
                holder.ui.btnEditRoom.setOnClickListener {
                    val p = holder.bindingAdapterPosition
                    if (p != RecyclerView.NO_POSITION && p < rooms.size) onEdit(p)
                }
                holder.ui.btnDeleteRoom.setOnClickListener {
                    val p = holder.bindingAdapterPosition
                    if (p != RecyclerView.NO_POSITION && p < rooms.size) onDelete(p)
                }
                holder.ui.root.setOnLongClickListener {
                    val p = holder.bindingAdapterPosition
                    if (p != RecyclerView.NO_POSITION && p < rooms.size) onLongPress(p)
                    true
                }
            } else if (holder is MoreHolder) {
                val button = holder.itemView as android.widget.Button
                button.text = if (isExpanded) holder.itemView.context.getString(R.string.show_less_rooms) else holder.itemView.context.getString(R.string.show_more_rooms)
            }
        }

        fun setExpanded(expanded: Boolean) {
            isExpanded = expanded
            notifyItemRangeChanged(0, itemCount)
        }

        fun setToggleCallback(callback: (() -> Unit)?) {
            onToggleExpand = callback
        }
    }

    class MoreHolder(itemView: android.widget.Button) : RecyclerView.ViewHolder(itemView)
}

package au.edu.utas.kit305.tutorial05

import android.annotation.SuppressLint
import android.app.AlertDialog
import android.content.Intent
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.util.Log
import android.view.ViewGroup
import android.widget.EditText
import android.widget.LinearLayout
import androidx.core.widget.doAfterTextChanged
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import au.edu.utas.kit305.tutorial05.databinding.ActivityMainBinding
import au.edu.utas.kit305.tutorial05.databinding.HouseListItemBinding

import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.firestore.toObject
import com.google.firebase.ktx.Firebase

const val FIREBASE_TAG = "FirebaseLogging"
const val HOUSE_INDEX = "House_Index"
const val MOVIE_INDEX = "Movie_Index"
const val HOUSE_NAME_EXTRA = "house_name"
val items = mutableListOf<Movie>()
val houses = mutableListOf<House>()

class MainActivity : AppCompatActivity() {
    private lateinit var ui: ActivityMainBinding
    private var housesExpanded = false
    private val filteredHouses = mutableListOf<House>()
    private var houseSearchQuery: String = ""

    @SuppressLint("SetTextI18n")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        ui = ActivityMainBinding.inflate(layoutInflater)
        setContentView(ui.root)

        ui.lblMovieCount.text = getString(R.string.house_count_format, houses.size)
        val houseAdapter = HouseAdapter(houseList = filteredHouses)
        houseAdapter.setToggleCallback {
            housesExpanded = !housesExpanded
            houseAdapter.setExpanded(housesExpanded)
        }
        ui.myList.adapter = houseAdapter

        ui.myList.layoutManager = LinearLayoutManager(this)
        ui.btnAddHouse.setOnClickListener { addHouse() }
        ui.txtSearchHouses.doAfterTextChanged {
            houseSearchQuery = it?.toString()?.trim().orEmpty()
            applyHouseFilter()
        }

        val db = Firebase.firestore
        Log.d("FIREBASE", "Firebase connected: ${db.app.name}")

        val housesCollection = db.collection("houses")
        ui.lblMovieCount.text = "Loading..."
        housesCollection
            .get()
            .addOnSuccessListener { result ->
                houses.clear()
                for (document in result) {
                    val house = document.toObject<House>()
                    house.id = document.id
                    houses.add(house)
                }
                applyHouseFilter()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error reading houses", it)
                ui.lblMovieCount.text = getString(R.string.house_count_format, 0)
            }
    }

    override fun onResume() {
        super.onResume()
        applyHouseFilter()
    }

    private fun addHouse() {
        val newHouse = House(customerName = "New Customer", address = "New Address")

        Firebase.firestore.collection("houses")
            .add(newHouse)
            .addOnSuccessListener {
                newHouse.id = it.id
                houses.add(0, newHouse)
                applyHouseFilter()
                ui.myList.scrollToPosition(0)
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error creating house", it)
            }
    }

    private fun promptDeleteHouse(house: House) {

        AlertDialog.Builder(this)
            .setMessage(R.string.delete_house_confirm)
            .setPositiveButton(R.string.delete) { _, _ -> deleteHouse(house) }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    private fun showEditHouseDialog(house: House) {

        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            val p = (16 * resources.displayMetrics.density).toInt()
            setPadding(p, p, p, 0)
        }

        val nameEdit = EditText(this).apply {
            hint = "Customer name"
            setText(house.customerName ?: "")
        }

        val addressEdit = EditText(this).apply {
            hint = "Address"
            setText(house.address ?: "")
        }

        layout.addView(nameEdit)
        layout.addView(addressEdit)

        AlertDialog.Builder(this)
            .setTitle("Edit House")
            .setView(layout)
            .setPositiveButton("Save") { _, _ ->
                val newName = nameEdit.text.toString().trim()
                val newAddress = addressEdit.text.toString().trim()
                if (newName.isBlank() || newAddress.isBlank()) return@setPositiveButton
                updateHouse(house, newName, newAddress)
            }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    private fun updateHouse(house: House, customerName: String, address: String) {
        val houseId = house.id ?: return

        val updates = mapOf(
            "customerName" to customerName,
            "address" to address
        )

        Firebase.firestore.collection("houses").document(houseId)
            .update(updates)
            .addOnSuccessListener {
                house.customerName = customerName
                house.address = address
                applyHouseFilter()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error updating house", it)
            }
    }

    private fun deleteHouse(house: House) {
        val houseId = house.id ?: return

        val db = Firebase.firestore
        db.collection("rooms")
            .whereEqualTo("houseId", houseId)
            .get()
            .addOnSuccessListener { result ->
                val batch = db.batch()
                for (document in result.documents) {
                    batch.delete(document.reference)
                }
                batch.delete(db.collection("houses").document(houseId))

                batch.commit()
                    .addOnSuccessListener {
                        houses.removeAll { it.id == houseId }
                        applyHouseFilter()
                    }
                    .addOnFailureListener {
                        Log.e(FIREBASE_TAG, "Error deleting house and rooms", it)
                    }
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error finding rooms for house delete", it)
            }
    }

    private fun openQuoteFromHouse(house: House) {
        val houseId = house.id ?: return

        val i = Intent(this, QuoteActivity::class.java)
        i.putExtra(HOUSE_ID_EXTRA, houseId)
        i.putExtra(HOUSE_NAME_EXTRA, house.customerName ?: getString(R.string.quote_title_default))
        startActivity(i)
    }

    private fun openRoomsFromHouse(house: House) {
        val i = Intent(this, HouseDetails::class.java)
        i.putExtra(HOUSE_INDEX, -1)
        i.putExtra(HOUSE_ID_EXTRA, house.id)
        i.putExtra(HOUSE_NAME_EXTRA, house.customerName ?: "House")
        startActivity(i)
    }

    private fun applyHouseFilter() {
        val q = houseSearchQuery.lowercase()
        filteredHouses.clear()
        if (q.isBlank()) {
            filteredHouses.addAll(houses)
        } else {
            filteredHouses.addAll(
                houses.filter { house ->
                    val name = house.customerName.orEmpty().lowercase()
                    val address = house.address.orEmpty().lowercase()
                    name.contains(q) || address.contains(q)
                }
            )
        }
        ui.myList.adapter?.notifyDataSetChanged()
        ui.lblMovieCount.text = getString(R.string.house_count_format, filteredHouses.size)
    }

    private fun showHouseTapOptions(position: Int) {
        if (position < 0 || position >= houses.size) return

        AlertDialog.Builder(this)
            .setTitle(R.string.house_actions_title)
            .setItems(arrayOf(getString(R.string.edit_house_action), getString(R.string.open_rooms_action))) { _, which ->
                when (which) {
                    0 -> showEditHouseDialog(houses[position])
                    1 -> {
                        val i = Intent(this, HouseDetails::class.java)
                        i.putExtra(HOUSE_INDEX, position)
                        i.putExtra(HOUSE_ID_EXTRA, houses[position].id)
                        i.putExtra(HOUSE_NAME_EXTRA, houses[position].customerName ?: "House")
                        startActivity(i)
                    }
                }
            }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    inner class HouseHolder(var ui: HouseListItemBinding) : RecyclerView.ViewHolder(ui.root)
    inner class MoreHolder(itemView: android.widget.Button) : RecyclerView.ViewHolder(itemView)

    inner class HouseAdapter(private val houseList: MutableList<House>) : RecyclerView.Adapter<RecyclerView.ViewHolder>() {

        private val itemTypeHouse = 0
        private val itemTypeToggle = 1
        private val itemsPerPage = 2

        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): RecyclerView.ViewHolder {
            return if (viewType == itemTypeHouse) {
                val ui = HouseListItemBinding.inflate(layoutInflater, parent, false)
                HouseHolder(ui)
            } else {
                val button = android.widget.Button(parent.context)
                button.setOnClickListener { onToggleExpand?.invoke() }
                button.layoutParams = ViewGroup.LayoutParams(
                    ViewGroup.LayoutParams.MATCH_PARENT,
                    ViewGroup.LayoutParams.WRAP_CONTENT
                )
                MoreHolder(button)
            }
        }

        override fun getItemCount(): Int {
            val visibleCount = if (isExpanded) houseList.size else minOf(itemsPerPage, houseList.size)
            val hasToggle = houseList.size > itemsPerPage
            return visibleCount + (if (hasToggle) 1 else 0)
        }

        override fun getItemViewType(position: Int): Int {
            val visibleCount = if (isExpanded) houseList.size else minOf(itemsPerPage, houseList.size)
            return if (position < visibleCount) itemTypeHouse else itemTypeToggle
        }

        override fun onBindViewHolder(holder: RecyclerView.ViewHolder, position: Int) {
            if (holder is HouseHolder && position < houseList.size) {
                val house = houseList[position]
                holder.ui.txtName.text = house.customerName ?: "Unnamed customer"
                holder.ui.txtAddress.text = house.address ?: "No address"

                holder.ui.root.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openRoomsFromHouse(house)
                }

                holder.ui.btnEditHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    showEditHouseDialog(house)
                }

                holder.ui.btnCreateRoomHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openRoomsFromHouse(house)
                }

                holder.ui.btnDeleteHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    promptDeleteHouse(house)
                }

                holder.ui.btnViewQuoteHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openQuoteFromHouse(house)
                }
            } else if (holder is MoreHolder) {
                val button = holder.itemView as android.widget.Button
                button.text = if (isExpanded) "Show Less Houses" else "Show More Houses"
            }
        }

        fun setExpanded(expanded: Boolean) {
            isExpanded = expanded
            notifyDataSetChanged()
        }

        fun setToggleCallback(callback: (() -> Unit)?) {
            onToggleExpand = callback
        }

        private var isExpanded: Boolean = false
        private var onToggleExpand: (() -> Unit)? = null
    }
}

package au.edu.utas.kit305.tutorial05

import android.annotation.SuppressLint
import android.app.AlertDialog
import android.content.Intent
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.util.Log
import android.view.ViewGroup
import android.widget.EditText
import android.widget.LinearLayout
import androidx.core.widget.doAfterTextChanged
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import au.edu.utas.kit305.tutorial05.databinding.ActivityMainBinding
import au.edu.utas.kit305.tutorial05.databinding.HouseListItemBinding

import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.firestore.toObject
import com.google.firebase.ktx.Firebase

const val FIREBASE_TAG = "FirebaseLogging"
const val HOUSE_INDEX = "House_Index"
const val MOVIE_INDEX = "Movie_Index"
const val HOUSE_NAME_EXTRA = "house_name"
val items = mutableListOf<Movie>()
val houses = mutableListOf<House>()

class MainActivity : AppCompatActivity() {
    private lateinit var ui: ActivityMainBinding
    private var housesExpanded = false
    private val filteredHouses = mutableListOf<House>()
    private var houseSearchQuery: String = ""

    @SuppressLint("SetTextI18n")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        ui = ActivityMainBinding.inflate(layoutInflater)
        setContentView(ui.root)

        ui.lblMovieCount.text = getString(R.string.house_count_format, houses.size)
        val houseAdapter = HouseAdapter(houseList = filteredHouses)
        houseAdapter.setToggleCallback {
            housesExpanded = !housesExpanded
            houseAdapter.setExpanded(housesExpanded)
        }
        ui.myList.adapter = houseAdapter

        ui.myList.layoutManager = LinearLayoutManager(this)
        ui.btnAddHouse.setOnClickListener { showAddHouseDialog() }
        ui.txtSearchHouses.doAfterTextChanged {
            houseSearchQuery = it?.toString()?.trim().orEmpty()
            applyHouseFilter()
        }

        val db = Firebase.firestore
        Log.d("FIREBASE", "Firebase connected: ${db.app.name}")

        val housesCollection = db.collection("houses")
        ui.lblMovieCount.text = "Loading..."
        housesCollection
            .get()
            .addOnSuccessListener { result ->
                houses.clear()
                for (document in result) {
                    val house = document.toObject<House>()
                    house.id = document.id
                    houses.add(house)
                }
                applyHouseFilter()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error reading houses", it)
                ui.lblMovieCount.text = getString(R.string.house_count_format, 0)
            }
    }

    override fun onResume() {
        super.onResume()
        applyHouseFilter()
    }

    private fun showAddHouseDialog() {
        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            val p = (16 * resources.displayMetrics.density).toInt()
            setPadding(p, p, p, 0)
        }

        val nameEdit = EditText(this).apply {
            hint = getString(R.string.house_dialog_customer_name_hint)
        }

        val addressEdit = EditText(this).apply {
            hint = getString(R.string.house_dialog_address_hint)
        }

        layout.addView(nameEdit)
        layout.addView(addressEdit)

        val dialog = AlertDialog.Builder(this)
            .setTitle(R.string.house_dialog_add_title)
            .setView(layout)
            .setPositiveButton(R.string.save, null)
            .setNegativeButton(R.string.cancel, null)
            .create()

        dialog.setOnShowListener {
            dialog.getButton(AlertDialog.BUTTON_POSITIVE).setOnClickListener {
                val newName = nameEdit.text.toString().trim()
                val newAddress = addressEdit.text.toString().trim()

                val valid = validateHouseInput(nameEdit, addressEdit, newName, newAddress)
                if (!valid) return@setOnClickListener

                addHouse(newName, newAddress)
                dialog.dismiss()
            }
        }

        dialog.show()
    }

    private fun addHouse(customerName: String, address: String) {
        val newHouse = House(customerName = customerName, address = address)

        Firebase.firestore.collection("houses")
            .add(newHouse)
            .addOnSuccessListener {
                newHouse.id = it.id
                houses.add(0, newHouse)
                applyHouseFilter()
                ui.myList.scrollToPosition(0)
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error creating house", it)
            }
    }

    private fun promptDeleteHouse(house: House) {

        AlertDialog.Builder(this)
            .setMessage(R.string.delete_house_confirm)
            .setPositiveButton(R.string.delete) { _, _ -> deleteHouse(house) }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    private fun showEditHouseDialog(house: House) {

        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            val p = (16 * resources.displayMetrics.density).toInt()
            setPadding(p, p, p, 0)
        }

        val nameEdit = EditText(this).apply {
            hint = getString(R.string.house_dialog_customer_name_hint)
            setText(house.customerName ?: "")
        }

        val addressEdit = EditText(this).apply {
            hint = getString(R.string.house_dialog_address_hint)
            setText(house.address ?: "")
        }

        layout.addView(nameEdit)
        layout.addView(addressEdit)

        val dialog = AlertDialog.Builder(this)
            .setTitle(R.string.house_dialog_edit_title)
            .setView(layout)
            .setPositiveButton(R.string.save, null)
            .setNegativeButton(R.string.cancel, null)
            .create()

        dialog.setOnShowListener {
            dialog.getButton(AlertDialog.BUTTON_POSITIVE).setOnClickListener {
                val newName = nameEdit.text.toString().trim()
                val newAddress = addressEdit.text.toString().trim()

                val valid = validateHouseInput(nameEdit, addressEdit, newName, newAddress)
                if (!valid) return@setOnClickListener

                updateHouse(house, newName, newAddress)
                dialog.dismiss()
            }
        }

        dialog.show()
    }

    private fun containsLetter(value: String): Boolean = value.any { it.isLetter() }

    private fun validateHouseInput(
        nameEdit: EditText,
        addressEdit: EditText,
        newName: String,
        newAddress: String
    ): Boolean {
        var valid = true

        if (newName.isBlank()) {
            nameEdit.error = getString(R.string.error_customer_name_required)
            valid = false
        } else {
            nameEdit.error = null
        }

        when {
            newAddress.isBlank() -> {
                addressEdit.error = getString(R.string.error_address_required)
                valid = false
            }
            !containsLetter(newAddress) -> {
                // Prevent numeric-only addresses like "12345".
                addressEdit.error = getString(R.string.error_address_requires_letter)
                valid = false
            }
            else -> addressEdit.error = null
        }

        return valid
    }

    private fun updateHouse(house: House, customerName: String, address: String) {
        val houseId = house.id ?: return

        val updates = mapOf(
            "customerName" to customerName,
            "address" to address
        )

        Firebase.firestore.collection("houses").document(houseId)
            .update(updates)
            .addOnSuccessListener {
                house.customerName = customerName
                house.address = address
                applyHouseFilter()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error updating house", it)
            }
    }

    private fun deleteHouse(house: House) {
        val houseId = house.id ?: return

        val db = Firebase.firestore
        db.collection("rooms")
            .whereEqualTo("houseId", houseId)
            .get()
            .addOnSuccessListener { result ->
                val batch = db.batch()
                for (document in result.documents) {
                    batch.delete(document.reference)
                }
                batch.delete(db.collection("houses").document(houseId))

                batch.commit()
                    .addOnSuccessListener {
                        houses.removeAll { it.id == houseId }
                        applyHouseFilter()
                    }
                    .addOnFailureListener {
                        Log.e(FIREBASE_TAG, "Error deleting house and rooms", it)
                    }
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error finding rooms for house delete", it)
            }
    }

    private fun openQuoteFromHouse(house: House) {
        val houseId = house.id ?: return

        val i = Intent(this, QuoteActivity::class.java)
        i.putExtra(HOUSE_ID_EXTRA, houseId)
        i.putExtra(HOUSE_NAME_EXTRA, house.customerName ?: getString(R.string.quote_title_default))
        startActivity(i)
    }

    private fun openRoomsFromHouse(house: House) {
        val i = Intent(this, HouseDetails::class.java)
        i.putExtra(HOUSE_INDEX, -1)
        i.putExtra(HOUSE_ID_EXTRA, house.id)
        i.putExtra(HOUSE_NAME_EXTRA, house.customerName ?: "House")
        startActivity(i)
    }

    private fun applyHouseFilter() {
        val q = houseSearchQuery.lowercase()
        val oldSize = filteredHouses.size
        filteredHouses.clear()
        ui.myList.adapter?.notifyItemRangeRemoved(0, oldSize)
        if (q.isBlank()) {
            filteredHouses.addAll(houses)
        } else {
            filteredHouses.addAll(
                houses.filter { house ->
                    val name = house.customerName.orEmpty().lowercase()
                    val address = house.address.orEmpty().lowercase()
                    name.contains(q) || address.contains(q)
                }
            )
        }
        ui.myList.adapter?.notifyItemRangeInserted(0, filteredHouses.size)
        ui.lblMovieCount.text = getString(R.string.house_count_format, filteredHouses.size)
    }

    private fun showHouseTapOptions(position: Int) {
        if (position < 0 || position >= houses.size) return

        AlertDialog.Builder(this)
            .setTitle(R.string.house_actions_title)
            .setItems(arrayOf(getString(R.string.edit_house_action), getString(R.string.open_rooms_action))) { _, which ->
                when (which) {
                    0 -> showEditHouseDialog(houses[position])
                    1 -> {
                        val i = Intent(this, HouseDetails::class.java)
                        i.putExtra(HOUSE_INDEX, position)
                        i.putExtra(HOUSE_ID_EXTRA, houses[position].id)
                        i.putExtra(HOUSE_NAME_EXTRA, houses[position].customerName ?: "House")
                        startActivity(i)
                    }
                }
            }
            .setNegativeButton(R.string.cancel, null)
            .show()
    }

    inner class HouseHolder(var ui: HouseListItemBinding) : RecyclerView.ViewHolder(ui.root)
    inner class MoreHolder(itemView: android.widget.Button) : RecyclerView.ViewHolder(itemView)

    inner class HouseAdapter(private val houseList: MutableList<House>) : RecyclerView.Adapter<RecyclerView.ViewHolder>() {

        private val itemTypeHouse = 0
        private val itemTypeToggle = 1
        private val itemsPerPage = 2

        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): RecyclerView.ViewHolder {
            return if (viewType == itemTypeHouse) {
                val ui = HouseListItemBinding.inflate(layoutInflater, parent, false)
                HouseHolder(ui)
            } else {
                val button = android.widget.Button(parent.context)
                button.setOnClickListener { onToggleExpand?.invoke() }
                button.layoutParams = ViewGroup.LayoutParams(
                    ViewGroup.LayoutParams.MATCH_PARENT,
                    ViewGroup.LayoutParams.WRAP_CONTENT
                )
                MoreHolder(button)
            }
        }

        override fun getItemCount(): Int {
            val visibleCount = if (isExpanded) houseList.size else minOf(itemsPerPage, houseList.size)
            val hasToggle = houseList.size > itemsPerPage
            return visibleCount + (if (hasToggle) 1 else 0)
        }

        override fun getItemViewType(position: Int): Int {
            val visibleCount = if (isExpanded) houseList.size else minOf(itemsPerPage, houseList.size)
            return if (position < visibleCount) itemTypeHouse else itemTypeToggle
        }

        override fun onBindViewHolder(holder: RecyclerView.ViewHolder, position: Int) {
            if (holder is HouseHolder && position < houseList.size) {
                val house = houseList[position]
                holder.ui.txtName.text = house.customerName ?: getString(R.string.unnamed_customer)
                holder.ui.txtAddress.text = house.address ?: getString(R.string.no_address)

                holder.ui.root.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openRoomsFromHouse(house)
                }

                holder.ui.btnEditHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    showEditHouseDialog(house)
                }

                holder.ui.btnCreateRoomHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openRoomsFromHouse(house)
                }

                holder.ui.btnDeleteHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    promptDeleteHouse(house)
                }

                holder.ui.btnViewQuoteHouse.setOnClickListener {
                    val currentPosition = holder.bindingAdapterPosition
                    if (currentPosition == RecyclerView.NO_POSITION) return@setOnClickListener
                    openQuoteFromHouse(house)
                }
            } else if (holder is MoreHolder) {
                val button = holder.itemView as android.widget.Button
                button.text = if (isExpanded) getString(R.string.show_less_houses) else getString(R.string.show_more_houses)
            }
        }

        fun setExpanded(expanded: Boolean) {
            isExpanded = expanded
            notifyItemRangeChanged(0, itemCount)
        }

        fun setToggleCallback(callback: (() -> Unit)?) {
            onToggleExpand = callback
        }

        private var isExpanded: Boolean = false
        private var onToggleExpand: (() -> Unit)? = null
    }
}

package au.edu.utas.kit305.tutorial05

import android.content.Intent
import android.os.Bundle
import android.util.Log
import android.view.ViewGroup
import android.widget.Button
import android.widget.CheckBox
import android.widget.EditText
import android.widget.LinearLayout
import android.widget.TextView
import androidx.core.widget.doAfterTextChanged
import androidx.appcompat.app.AppCompatActivity
import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.firestore.toObject
import com.google.firebase.ktx.Firebase
import org.json.JSONArray
import org.json.JSONObject
import java.net.HttpURLConnection
import java.net.URL
import java.util.Locale

class QuoteActivity : AppCompatActivity() {

    companion object {
        private const val DEFAULT_WINDOW_RATE = 50.0
        private const val DEFAULT_FLOOR_RATE = 100.0
        private const val ROOM_LABOUR = 200.0
        private const val QUOTE_SECTION_PREVIEW_COUNT = 2
    }

    private data class RoomQuoteData(
        val room: Room,
        val windows: List<Window>,
        val floorSpaces: List<FloorSpace>
    )

    private lateinit var lblQuoteTitle: TextView
    private lateinit var lblQuoteAddress: TextView
    private lateinit var lblQuoteStatus: TextView
    private lateinit var lblQuoteTotal: TextView
    private lateinit var lblDiscountSummary: TextView
    private lateinit var edtDiscountPercent: EditText
    private lateinit var btnApplyDiscount: Button
    private lateinit var btnClearDiscount: Button
    private lateinit var btnShareQuote: Button
    private lateinit var layoutQuoteContent: LinearLayout
    private lateinit var houseId: String
    private var currentRoomQuotes: List<RoomQuoteData> = emptyList()
    private var currentProductRates: Map<String, Double> = emptyMap()
    private var currentUsingDefaults: Boolean = false
    private val includedRooms = mutableMapOf<String, Boolean>()
    private val includedItems = mutableMapOf<String, Boolean>()
    private val expandedWindowsByRoom = mutableMapOf<String, Boolean>()
    private val expandedFloorsByRoom = mutableMapOf<String, Boolean>()
    private var discountPercent: Double = 0.0

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_quote)

        lblQuoteTitle = findViewById(R.id.lblQuoteTitle)
        lblQuoteAddress = findViewById(R.id.lblQuoteAddress)
        lblQuoteStatus = findViewById(R.id.lblQuoteStatus)
        lblQuoteTotal = findViewById(R.id.lblQuoteTotal)
        lblDiscountSummary = findViewById(R.id.lblDiscountSummary)
        edtDiscountPercent = findViewById(R.id.edtDiscountPercent)
        btnApplyDiscount = findViewById(R.id.btnApplyDiscount)
        btnClearDiscount = findViewById(R.id.btnClearDiscount)
        btnShareQuote = findViewById(R.id.btnShareQuote)
        layoutQuoteContent = findViewById(R.id.layoutQuoteContent)
        lblDiscountSummary.text = getString(R.string.discount_none)
        btnApplyDiscount.setOnClickListener { applyDiscountFromInput() }
        btnClearDiscount.setOnClickListener { clearDiscount() }
        btnShareQuote.setOnClickListener { shareQuoteText() }
        edtDiscountPercent.doAfterTextChanged {
            edtDiscountPercent.error = null
            updateDiscountButtons()
        }
        updateDiscountButtons()

        houseId = intent.getStringExtra(HOUSE_ID_EXTRA) ?: run {
            finish()
            return
        }

        val houseName = intent.getStringExtra(HOUSE_NAME_EXTRA)
            ?.takeIf { it.isNotBlank() }
            ?: getString(R.string.quote_title_default)

        title = getString(R.string.quote_title_default)
        lblQuoteTitle.text = houseName
        lblQuoteStatus.text = getString(R.string.quote_loading)
        lblQuoteTotal.text = getString(R.string.quote_total_format, 0.0)

        loadHouseAndRooms()
    }

    private fun loadHouseAndRooms() {
        Firebase.firestore.collection("houses").document(houseId).get()
            .addOnSuccessListener { document ->
                val house = document.toObject<House>()
                lblQuoteTitle.text = house?.customerName?.takeIf { it.isNotBlank() }
                    ?: lblQuoteTitle.text
                lblQuoteAddress.text = house?.address?.takeIf { it.isNotBlank() }
                    ?: getString(R.string.quote_address_missing)
                loadRooms()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error loading house for quote", it)
                lblQuoteAddress.text = getString(R.string.quote_address_missing)
                loadRooms()
            }
    }

    private fun loadRooms() {
        Firebase.firestore.collection("rooms")
            .whereEqualTo("houseId", houseId)
            .get()
            .addOnSuccessListener { result ->
                val rooms = result.documents.mapNotNull { doc ->
                    doc.toObject<Room>()?.apply { id = doc.id }
                }

                if (rooms.isEmpty()) {
                    layoutQuoteContent.removeAllViews()
                    lblQuoteStatus.text = getString(R.string.quote_no_rooms)
                    return@addOnSuccessListener
                }

                val pending = intArrayOf(rooms.size)
                val loadedRooms = mutableListOf<RoomQuoteData>()

                rooms.forEach { room ->
                    loadRoomMeasurements(room,
                        onLoaded = { roomData ->
                            loadedRooms.add(roomData)
                            pending[0] -= 1
                            if (pending[0] == 0) {
                                loadProductsAndRender(loadedRooms.sortedBy { it.room.name ?: "" })
                            }
                        },
                        onFailed = {
                            pending[0] -= 1
                            if (pending[0] == 0) {
                                loadProductsAndRender(loadedRooms.sortedBy { it.room.name ?: "" })
                            }
                        }
                    )
                }
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error loading rooms for quote", it)
                layoutQuoteContent.removeAllViews()
                lblQuoteStatus.text = getString(R.string.quote_no_rooms)
                lblQuoteTotal.text = getString(R.string.quote_total_format, 0.0)
            }
    }

    private fun loadProductsAndRender(roomQuotes: List<RoomQuoteData>) {
        lblQuoteStatus.text = getString(R.string.quote_loading)

        Thread {
            try {
                val endpoint = "https://utasbot.dev/kit305_2026/product"
                val connection = (URL(endpoint).openConnection() as HttpURLConnection).apply {
                    requestMethod = "GET"
                    connectTimeout = 10000
                    readTimeout = 10000
                }

                val responseCode = connection.responseCode
                if (responseCode !in 200..299) {
                    connection.disconnect()
                    runOnUiThread { showQuote(roomQuotes, emptyMap(), true) }
                    return@Thread
                }

                val responseText = connection.inputStream.bufferedReader().use { it.readText() }
                connection.disconnect()

                val productRates = parseProductRates(responseText)
                runOnUiThread { showQuote(roomQuotes, productRates, false) }
            } catch (e: Exception) {
                Log.e(FIREBASE_TAG, "Error loading quote product prices", e)
                runOnUiThread { showQuote(roomQuotes, emptyMap(), true) }
            }
        }.start()
    }

    private fun showQuote(
        roomQuotes: List<RoomQuoteData>,
        productRates: Map<String, Double>,
        usingDefaults: Boolean
    ) {
        currentRoomQuotes = roomQuotes
        currentProductRates = productRates
        currentUsingDefaults = usingDefaults

        // Rebuild include maps per fresh quote load to avoid stale hidden states.
        includedRooms.clear()
        includedItems.clear()
        expandedWindowsByRoom.clear()
        expandedFloorsByRoom.clear()

        for (roomQuote in roomQuotes) {
            val roomId = roomQuote.room.id ?: continue
            includedRooms[roomId] = true
            roomQuote.windows.forEachIndexed { index, window ->
                val key = buildItemKey("window", roomId, window.id, window.name ?: "", index)
                includedItems[key] = true
            }
            roomQuote.floorSpaces.forEachIndexed { index, floorSpace ->
                val key = buildItemKey("floor", roomId, floorSpace.id, floorSpace.name ?: "", index)
                includedItems[key] = true
            }
        }
        renderRooms()
    }

    private fun loadRoomMeasurements(
        room: Room,
        onLoaded: (RoomQuoteData) -> Unit,
        onFailed: () -> Unit
    ) {
        val roomId = room.id ?: run {
            onFailed()
            return
        }

        Firebase.firestore.collection("windows")
            .whereEqualTo("roomId", roomId)
            .get()
            .addOnSuccessListener { windowResult ->
                val windows = windowResult.documents.mapNotNull { doc ->
                    doc.toObject<Window>()?.apply { id = doc.id }
                }

                Firebase.firestore.collection("floorspaces")
                    .whereEqualTo("roomId", roomId)
                    .get()
                    .addOnSuccessListener { floorResult ->
                        val floorSpaces = floorResult.documents.mapNotNull { doc ->
                            doc.toObject<FloorSpace>()?.apply { id = doc.id }
                        }
                        onLoaded(RoomQuoteData(room, windows, floorSpaces))
                    }
                    .addOnFailureListener {
                        Log.e(FIREBASE_TAG, "Error loading floor spaces for quote", it)
                        onLoaded(RoomQuoteData(room, windows, emptyList()))
                    }
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error loading windows for quote", it)
                onLoaded(RoomQuoteData(room, emptyList(), emptyList()))
            }
    }

    private fun renderRooms() {
        layoutQuoteContent.removeAllViews()
        lblQuoteStatus.text = if (currentUsingDefaults) getString(R.string.quote_using_defaults) else ""

        var houseTotal = 0.0

        for (roomQuote in currentRoomQuotes) {
            val roomId = roomQuote.room.id ?: continue
            val roomName = roomQuote.room.name?.ifBlank { "Unnamed room" } ?: "Unnamed room"
            val includeRoom = includedRooms[roomId] != false

            val roomToggle = CheckBox(this).apply {
                text = getString(R.string.quote_room_include_format, roomName)
                isChecked = includeRoom
                textSize = 16f
                setOnCheckedChangeListener { _, checked ->
                    includedRooms[roomId] = checked
                    renderRooms()
                }
            }
            roomToggle.layoutParams = LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
            ).apply {
                topMargin = (12 * resources.displayMetrics.density).toInt()
            }
            layoutQuoteContent.addView(roomToggle)

            var roomSubtotal = 0.0
            var hasMeasuredIncludedItem = false
            val roomTitle = makeText(
                getString(
                    R.string.quote_room_heading,
                    roomName
                ),
                18f,
                leftPaddingDp = 12,
                topMarginDp = 4
            )
            layoutQuoteContent.addView(roomTitle)

            if (!includeRoom) {
                layoutQuoteContent.addView(
                    makeText(
                        getString(R.string.quote_room_excluded),
                        14f,
                        leftPaddingDp = 12,
                        topMarginDp = 4
                    )
                )
                continue
            }

            val hasItems = roomQuote.windows.isNotEmpty() || roomQuote.floorSpaces.isNotEmpty()
            if (!hasItems) {
                layoutQuoteContent.addView(makeText(getString(R.string.quote_no_items), 14f, leftPaddingDp = 12))
            } else {
                val windowsExpanded = expandedWindowsByRoom[roomId] == true
                val floorsExpanded = expandedFloorsByRoom[roomId] == true

                roomQuote.windows.forEachIndexed { index, window ->
                    val itemKey = buildItemKey("window", roomId, window.id, window.name ?: "", index)
                    val includeItem = includedItems[itemKey] != false
                    val showItem = windowsExpanded || index < QUOTE_SECTION_PREVIEW_COUNT

                    if (showItem) {
                        layoutQuoteContent.addView(
                            makeItemToggle(
                                getString(R.string.quote_window_label),
                                window.name?.ifBlank { "Unnamed" } ?: "Unnamed",
                                includeItem
                            ) { checked ->
                                includedItems[itemKey] = checked
                                renderRooms()
                            }
                        )
                    }

                    if (!includeItem) {
                        if (showItem) {
                            layoutQuoteContent.addView(
                                makeText(
                                    getString(R.string.quote_item_excluded, getString(R.string.quote_window_label)),
                                    13f,
                                    leftPaddingDp = 24,
                                    topMarginDp = 4
                                )
                            )
                        }
                        return@forEachIndexed
                    }

                    val productName = window.selectedProductName?.ifBlank { getString(R.string.quote_product_basic_window) }
                        ?: getString(R.string.quote_product_basic_window)
                    val rate = resolveRate(window.selectedProductId, currentProductRates, DEFAULT_WINDOW_RATE)
                    val area = calculateArea(window.widthMm, window.heightMm)
                    val itemCost = area * rate
                    if (area > 0.0) {
                        hasMeasuredIncludedItem = true
                    }
                    roomSubtotal += itemCost

                    if (!showItem) {
                        return@forEachIndexed
                    }

                    layoutQuoteContent.addView(
                        makeText(
                            getString(
                                R.string.quote_window_line,
                                window.name?.ifBlank { "Unnamed" } ?: "Unnamed",
                                window.widthMm,
                                window.heightMm
                            ),
                            14f,
                            leftPaddingDp = 12,
                            topMarginDp = 6
                        )
                    )
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_product_line, productName), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_area_format, area), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_rate_format, rate), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_cost_format, itemCost), 13f, leftPaddingDp = 24))
                    if (window.panelCount > 1) {
                        layoutQuoteContent.addView(makeText(getString(R.string.quote_item_panels_format, window.panelCount), 13f, leftPaddingDp = 24))
                    }
                }

                if (roomQuote.windows.size > QUOTE_SECTION_PREVIEW_COUNT) {
                    layoutQuoteContent.addView(
                        makeSectionToggleButton(
                            if (windowsExpanded) getString(R.string.quote_show_less_windows)
                            else getString(R.string.quote_show_more_windows)
                        ) {
                            expandedWindowsByRoom[roomId] = !windowsExpanded
                            renderRooms()
                        }
                    )
                }

                roomQuote.floorSpaces.forEachIndexed { index, floorSpace ->
                    val itemKey = buildItemKey("floor", roomId, floorSpace.id, floorSpace.name ?: "", index)
                    val includeItem = includedItems[itemKey] != false
                    val showItem = floorsExpanded || index < QUOTE_SECTION_PREVIEW_COUNT

                    if (showItem) {
                        layoutQuoteContent.addView(
                            makeItemToggle(
                                getString(R.string.quote_floor_label),
                                floorSpace.name?.ifBlank { "Unnamed" } ?: "Unnamed",
                                includeItem
                            ) { checked ->
                                includedItems[itemKey] = checked
                                renderRooms()
                            }
                        )
                    }

                    if (!includeItem) {
                        if (showItem) {
                            layoutQuoteContent.addView(
                                makeText(
                                    getString(R.string.quote_item_excluded, getString(R.string.quote_floor_label)),
                                    13f,
                                    leftPaddingDp = 24,
                                    topMarginDp = 4
                                )
                            )
                        }
                        return@forEachIndexed
                    }

                    val productName = floorSpace.selectedProductName?.ifBlank { getString(R.string.quote_product_basic_floor) }
                        ?: getString(R.string.quote_product_basic_floor)
                    val rate = resolveRate(floorSpace.selectedProductId, currentProductRates, DEFAULT_FLOOR_RATE)
                    val area = calculateArea(floorSpace.widthMm, floorSpace.depthMm)
                    val itemCost = area * rate
                    if (area > 0.0) {
                        hasMeasuredIncludedItem = true
                    }
                    roomSubtotal += itemCost

                    if (!showItem) {
                        return@forEachIndexed
                    }

                    layoutQuoteContent.addView(
                        makeText(
                            getString(
                                R.string.quote_floor_line,
                                floorSpace.name?.ifBlank { "Unnamed" } ?: "Unnamed",
                                floorSpace.widthMm,
                                floorSpace.depthMm
                            ),
                            14f,
                            leftPaddingDp = 12,
                            topMarginDp = 6
                        )
                    )
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_product_line, productName), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_area_format, area), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_rate_format, rate), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_cost_format, itemCost), 13f, leftPaddingDp = 24))
                }

                if (roomQuote.floorSpaces.size > QUOTE_SECTION_PREVIEW_COUNT) {
                    layoutQuoteContent.addView(
                        makeSectionToggleButton(
                            if (floorsExpanded) getString(R.string.quote_show_less_floors)
                            else getString(R.string.quote_show_more_floors)
                        ) {
                            expandedFloorsByRoom[roomId] = !floorsExpanded
                            renderRooms()
                        }
                    )
                }
            }

            val roomLabour = if (hasMeasuredIncludedItem) ROOM_LABOUR else 0.0
            val roomTotal = roomSubtotal + roomLabour
            houseTotal += roomTotal
            layoutQuoteContent.addView(makeText(getString(R.string.quote_room_subtotal_format, roomSubtotal), 14f, leftPaddingDp = 12, topMarginDp = 8))
            layoutQuoteContent.addView(makeText(getString(R.string.quote_room_labour_format, roomLabour), 14f, leftPaddingDp = 12))
            layoutQuoteContent.addView(makeText(getString(R.string.quote_room_total_format, roomTotal), 15f, leftPaddingDp = 12))
        }

        val discountAmount = houseTotal * (discountPercent / 100.0)
        val finalTotal = houseTotal - discountAmount

        lblDiscountSummary.text = if (discountPercent > 0.0) {
            getString(R.string.discount_applied_format, discountPercent, discountAmount)
        } else {
            getString(R.string.discount_none)
        }
        lblQuoteTotal.text = getString(R.string.quote_total_after_discount_format, finalTotal)
    }

    private fun shareQuoteText() {
        val sendIntent = Intent(Intent.ACTION_SEND).apply {
            type = "text/plain"
            putExtra(Intent.EXTRA_TEXT, buildShareText())
        }
        startActivity(Intent.createChooser(sendIntent, getString(R.string.share_quote_chooser)))
    }

    private fun applyDiscountFromInput() {
        val parsed = edtDiscountPercent.text?.toString()?.trim()?.toDoubleOrNull()
        if (parsed == null || parsed < 0.0 || parsed > 100.0) {
            edtDiscountPercent.error = getString(R.string.discount_invalid)
            return
        }

        edtDiscountPercent.error = null
        discountPercent = parsed
        val normalized = String.format(Locale.US, "%.1f", discountPercent)
        if (edtDiscountPercent.text?.toString() != normalized) {
            edtDiscountPercent.setText(normalized)
            edtDiscountPercent.setSelection(normalized.length)
        }
        updateDiscountButtons()
        renderRooms()
    }

    private fun clearDiscount() {
        discountPercent = 0.0
        edtDiscountPercent.setText("")
        edtDiscountPercent.error = null
        updateDiscountButtons()
        renderRooms()
    }

    private fun updateDiscountButtons() {
        val typedText = edtDiscountPercent.text?.toString()?.trim().orEmpty()
        val hasTypedValue = typedText.isNotEmpty()
        val typedValue = typedText.toDoubleOrNull()
        val hasValidValue = typedValue != null && typedValue in 0.0..100.0
        val valueChanged = hasValidValue && kotlin.math.abs((typedValue ?: 0.0) - discountPercent) > 0.0001

        btnApplyDiscount.isEnabled = hasValidValue && valueChanged
        btnClearDiscount.isEnabled = discountPercent > 0.0 || hasTypedValue
    }

    private fun buildShareText(): String {
        val titleText = lblQuoteTitle.text?.toString()?.ifBlank { getString(R.string.quote_title_default) }
            ?: getString(R.string.quote_title_default)
        val addressText = lblQuoteAddress.text?.toString()?.ifBlank { getString(R.string.quote_address_missing) }
            ?: getString(R.string.quote_address_missing)

        val summary = StringBuilder()
        summary.append(getString(R.string.quote_share_title_format, titleText)).append("\n")
        summary.append(getString(R.string.quote_share_address_format, addressText)).append("\n")

        if (currentUsingDefaults) {
            summary.append(getString(R.string.quote_using_defaults)).append("\n")
        }

        summary.append("\n")
        if (currentRoomQuotes.isEmpty()) {
            summary.append(getString(R.string.quote_no_rooms)).append("\n")
            summary.append(getString(R.string.quote_subtotal_format, 0.0)).append("\n")
            summary.append(getString(R.string.quote_discount_line_format, discountPercent, 0.0)).append("\n")
            summary.append(getString(R.string.quote_total_after_discount_format, 0.0))
            return summary.toString()
        }

        var houseTotal = 0.0
        var hasIncludedRoom = false

        for (roomQuote in currentRoomQuotes) {
            val roomId = roomQuote.room.id ?: continue
            if (includedRooms[roomId] == false) {
                continue
            }

            hasIncludedRoom = true
            val roomName = roomQuote.room.name?.ifBlank { "Unnamed room" } ?: "Unnamed room"
            summary.append(getString(R.string.quote_room_heading, roomName)).append("\n")

            var roomSubtotal = 0.0
            var hasMeasuredIncludedItem = false

            roomQuote.windows.forEachIndexed { index, window ->
                val itemKey = buildItemKey("window", roomId, window.id, window.name ?: "", index)
                if (includedItems[itemKey] == false) {
                    return@forEachIndexed
                }

                val windowName = window.name?.ifBlank { "Unnamed" } ?: "Unnamed"
                val rate = resolveRate(window.selectedProductId, currentProductRates, DEFAULT_WINDOW_RATE)
                val area = calculateArea(window.widthMm, window.heightMm)
                val itemCost = area * rate
                if (area > 0.0) hasMeasuredIncludedItem = true
                roomSubtotal += itemCost

                summary.append("  ")
                    .append(getString(R.string.quote_window_line, windowName, window.widthMm, window.heightMm))
                    .append("\n")
                summary.append("  ")
                    .append(getString(R.string.quote_item_cost_format, itemCost))
                    .append("\n")
            }

            roomQuote.floorSpaces.forEachIndexed { index, floorSpace ->
                val itemKey = buildItemKey("floor", roomId, floorSpace.id, floorSpace.name ?: "", index)
                if (includedItems[itemKey] == false) {
                    return@forEachIndexed
                }

                val floorName = floorSpace.name?.ifBlank { "Unnamed" } ?: "Unnamed"
                val rate = resolveRate(floorSpace.selectedProductId, currentProductRates, DEFAULT_FLOOR_RATE)
                val area = calculateArea(floorSpace.widthMm, floorSpace.depthMm)
                val itemCost = area * rate
                if (area > 0.0) hasMeasuredIncludedItem = true
                roomSubtotal += itemCost

                summary.append("  ")
                    .append(getString(R.string.quote_floor_line, floorName, floorSpace.widthMm, floorSpace.depthMm))
                    .append("\n")
                summary.append("  ")
                    .append(getString(R.string.quote_item_cost_format, itemCost))
                    .append("\n")
            }

            val roomLabour = if (hasMeasuredIncludedItem) ROOM_LABOUR else 0.0
            val roomTotal = roomSubtotal + roomLabour
            houseTotal += roomTotal

            summary.append("  ").append(getString(R.string.quote_room_subtotal_format, roomSubtotal)).append("\n")
            summary.append("  ").append(getString(R.string.quote_room_labour_format, roomLabour)).append("\n")
            summary.append("  ").append(getString(R.string.quote_room_total_format, roomTotal)).append("\n\n")
        }

        if (!hasIncludedRoom) {
            summary.append(getString(R.string.quote_no_rooms)).append("\n")
            summary.append(getString(R.string.quote_subtotal_format, 0.0)).append("\n")
            summary.append(getString(R.string.quote_discount_line_format, discountPercent, 0.0)).append("\n")
            summary.append(getString(R.string.quote_total_after_discount_format, 0.0))
            return summary.toString()
        }

        val discountAmount = houseTotal * (discountPercent / 100.0)
        val finalTotal = houseTotal - discountAmount
        summary.append(getString(R.string.quote_subtotal_format, houseTotal)).append("\n")
        summary.append(getString(R.string.quote_discount_line_format, discountPercent, discountAmount)).append("\n")
        summary.append(getString(R.string.quote_total_after_discount_format, finalTotal))

        return summary.toString()
    }

    private fun buildItemKey(type: String, roomId: String, id: String?, fallbackName: String, index: Int): String {
        val stablePart = id ?: fallbackName
        return "$type:$roomId:$stablePart:$index"
    }

    private fun resolveRate(productId: String?, productRates: Map<String, Double>, defaultRate: Double): Double {
        if (productId.isNullOrBlank()) return defaultRate
        return productRates[productId] ?: defaultRate
    }

    private fun calculateArea(widthMm: Int, heightMm: Int): Double {
        return (widthMm / 1000.0) * (heightMm / 1000.0)
    }

    private fun parseProductRates(responseText: String): Map<String, Double> {
        val result = mutableMapOf<String, Double>()
        val array: JSONArray = if (responseText.trim().startsWith("{")) {
            val root = JSONObject(responseText)
            root.optJSONArray("data") ?: JSONArray()
        } else {
            JSONArray(responseText)
        }

        for (i in 0 until array.length()) {
            val obj = array.optJSONObject(i) ?: continue
            val id = obj.optString("id")
            if (id.isBlank()) continue
            result[id] = obj.optDouble("price_per_sqm", 0.0)
        }
        return result
    }

    private fun makeText(
        text: String,
        textSizeSp: Float,
        leftPaddingDp: Int = 0,
        topMarginDp: Int = 0
    ): TextView {
        val view = TextView(this)
        view.text = text
        view.textSize = textSizeSp

        val density = resources.displayMetrics.density
        val leftPaddingPx = (leftPaddingDp * density).toInt()
        view.setPadding(leftPaddingPx, view.paddingTop, view.paddingRight, view.paddingBottom)

        val params = LinearLayout.LayoutParams(
            ViewGroup.LayoutParams.MATCH_PARENT,
            ViewGroup.LayoutParams.WRAP_CONTENT
        )
        params.topMargin = (topMarginDp * density).toInt()
        view.layoutParams = params
        return view
    }

    private fun makeItemToggle(
        itemType: String,
        itemName: String,
        checked: Boolean,
        onChanged: (Boolean) -> Unit
    ): CheckBox {
        return CheckBox(this).apply {
            text = getString(R.string.quote_item_include_format, itemType, itemName)
            isChecked = checked
            textSize = 14f
            setPadding((12 * resources.displayMetrics.density).toInt(), paddingTop, paddingRight, paddingBottom)
            layoutParams = LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
            ).apply {
                topMargin = (6 * resources.displayMetrics.density).toInt()
            }
            setOnCheckedChangeListener { _, isChecked -> onChanged(isChecked) }
        }
    }

    private fun makeSectionToggleButton(text: String, onClick: () -> Unit): Button {
        return Button(this).apply {
            this.text = text
            layoutParams = LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
            ).apply {
                topMargin = (6 * resources.displayMetrics.density).toInt()
                marginStart = (12 * resources.displayMetrics.density).toInt()
                marginEnd = (12 * resources.displayMetrics.density).toInt()
            }
            setOnClickListener { onClick() }
        }
    }
}

package au.edu.utas.kit305.tutorial05

import android.content.Intent
import android.os.Bundle
import android.util.Log
import android.view.ViewGroup
import android.widget.Button
import android.widget.CheckBox
import android.widget.EditText
import android.widget.LinearLayout
import android.widget.TextView
import androidx.core.widget.doAfterTextChanged
import androidx.appcompat.app.AppCompatActivity
import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.firestore.toObject
import com.google.firebase.ktx.Firebase
import org.json.JSONArray
import org.json.JSONObject
import java.net.HttpURLConnection
import java.net.URL
import java.util.Locale

class QuoteActivity : AppCompatActivity() {

    companion object {
        private const val DEFAULT_WINDOW_RATE = 50.0
        private const val DEFAULT_FLOOR_RATE = 100.0
        private const val ROOM_LABOUR = 200.0
        private const val QUOTE_SECTION_PREVIEW_COUNT = 2
    }

    private data class RoomQuoteData(
        val room: Room,
        val windows: List<Window>,
        val floorSpaces: List<FloorSpace>
    )

    private lateinit var lblQuoteTitle: TextView
    private lateinit var lblQuoteAddress: TextView
    private lateinit var lblQuoteStatus: TextView
    private lateinit var lblQuoteTotal: TextView
    private lateinit var lblDiscountSummary: TextView
    private lateinit var edtDiscountPercent: EditText
    private lateinit var btnApplyDiscount: Button
    private lateinit var btnClearDiscount: Button
    private lateinit var btnShareQuote: Button
    private lateinit var layoutQuoteContent: LinearLayout
    private lateinit var houseId: String
    private var currentRoomQuotes: List<RoomQuoteData> = emptyList()
    private var currentProductRates: Map<String, Double> = emptyMap()
    private var currentUsingDefaults: Boolean = false
    private val includedRooms = mutableMapOf<String, Boolean>()
    private val includedItems = mutableMapOf<String, Boolean>()
    private val expandedWindowsByRoom = mutableMapOf<String, Boolean>()
    private val expandedFloorsByRoom = mutableMapOf<String, Boolean>()
    private var discountPercent: Double = 0.0

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_quote)

        lblQuoteTitle = findViewById(R.id.lblQuoteTitle)
        lblQuoteAddress = findViewById(R.id.lblQuoteAddress)
        lblQuoteStatus = findViewById(R.id.lblQuoteStatus)
        lblQuoteTotal = findViewById(R.id.lblQuoteTotal)
        lblDiscountSummary = findViewById(R.id.lblDiscountSummary)
        edtDiscountPercent = findViewById(R.id.edtDiscountPercent)
        btnApplyDiscount = findViewById(R.id.btnApplyDiscount)
        btnClearDiscount = findViewById(R.id.btnClearDiscount)
        btnShareQuote = findViewById(R.id.btnShareQuote)
        layoutQuoteContent = findViewById(R.id.layoutQuoteContent)
        lblDiscountSummary.text = getString(R.string.discount_none)
        btnApplyDiscount.setOnClickListener { applyDiscountFromInput() }
        btnClearDiscount.setOnClickListener { clearDiscount() }
        btnShareQuote.setOnClickListener { shareQuoteText() }
        edtDiscountPercent.doAfterTextChanged {
            edtDiscountPercent.error = null
            updateDiscountButtons()
        }
        updateDiscountButtons()

        houseId = intent.getStringExtra(HOUSE_ID_EXTRA) ?: run {
            finish()
            return
        }

        val houseName = intent.getStringExtra(HOUSE_NAME_EXTRA)
            ?.takeIf { it.isNotBlank() }
            ?: getString(R.string.quote_title_default)

        title = getString(R.string.quote_title_default)
        lblQuoteTitle.text = houseName
        lblQuoteStatus.text = getString(R.string.quote_loading)
        lblQuoteTotal.text = getString(R.string.quote_total_format, 0.0)

        loadHouseAndRooms()
    }

    private fun loadHouseAndRooms() {
        Firebase.firestore.collection("houses").document(houseId).get()
            .addOnSuccessListener { document ->
                val house = document.toObject<House>()
                lblQuoteTitle.text = house?.customerName?.takeIf { it.isNotBlank() }
                    ?: lblQuoteTitle.text
                lblQuoteAddress.text = house?.address?.takeIf { it.isNotBlank() }
                    ?: getString(R.string.quote_address_missing)
                loadRooms()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error loading house for quote", it)
                lblQuoteAddress.text = getString(R.string.quote_address_missing)
                loadRooms()
            }
    }

    private fun loadRooms() {
        Firebase.firestore.collection("rooms")
            .whereEqualTo("houseId", houseId)
            .get()
            .addOnSuccessListener { result ->
                val rooms = result.documents.mapNotNull { doc ->
                    doc.toObject<Room>()?.apply { id = doc.id }
                }

                if (rooms.isEmpty()) {
                    layoutQuoteContent.removeAllViews()
                    lblQuoteStatus.text = getString(R.string.quote_no_rooms)
                    return@addOnSuccessListener
                }

                val pending = intArrayOf(rooms.size)
                val loadedRooms = mutableListOf<RoomQuoteData>()

                rooms.forEach { room ->
                    loadRoomMeasurements(room,
                        onLoaded = { roomData ->
                            loadedRooms.add(roomData)
                            pending[0] -= 1
                            if (pending[0] == 0) {
                                loadProductsAndRender(loadedRooms.sortedBy { it.room.name ?: "" })
                            }
                        },
                        onFailed = {
                            pending[0] -= 1
                            if (pending[0] == 0) {
                                loadProductsAndRender(loadedRooms.sortedBy { it.room.name ?: "" })
                            }
                        }
                    )
                }
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error loading rooms for quote", it)
                layoutQuoteContent.removeAllViews()
                lblQuoteStatus.text = getString(R.string.quote_no_rooms)
                lblQuoteTotal.text = getString(R.string.quote_total_format, 0.0)
            }
    }

    private fun loadProductsAndRender(roomQuotes: List<RoomQuoteData>) {
        lblQuoteStatus.text = getString(R.string.quote_loading)

        Thread {
            try {
                val endpoint = "https://utasbot.dev/kit305_2026/product"
                val connection = (URL(endpoint).openConnection() as HttpURLConnection).apply {
                    requestMethod = "GET"
                    connectTimeout = 10000
                    readTimeout = 10000
                }

                val responseCode = connection.responseCode
                if (responseCode !in 200..299) {
                    connection.disconnect()
                    runOnUiThread { showQuote(roomQuotes, emptyMap(), true) }
                    return@Thread
                }

                val responseText = connection.inputStream.bufferedReader().use { it.readText() }
                connection.disconnect()

                val productRates = parseProductRates(responseText)
                runOnUiThread { showQuote(roomQuotes, productRates, false) }
            } catch (e: Exception) {
                Log.e(FIREBASE_TAG, "Error loading quote product prices", e)
                runOnUiThread { showQuote(roomQuotes, emptyMap(), true) }
            }
        }.start()
    }

    private fun showQuote(
        roomQuotes: List<RoomQuoteData>,
        productRates: Map<String, Double>,
        usingDefaults: Boolean
    ) {
        currentRoomQuotes = roomQuotes
        currentProductRates = productRates
        currentUsingDefaults = usingDefaults

        // Rebuild include maps per fresh quote load to avoid stale hidden states.
        includedRooms.clear()
        includedItems.clear()
        expandedWindowsByRoom.clear()
        expandedFloorsByRoom.clear()

        for (roomQuote in roomQuotes) {
            val roomId = roomQuote.room.id ?: continue
            includedRooms[roomId] = true
            roomQuote.windows.forEachIndexed { index, window ->
                val key = buildItemKey("window", roomId, window.id, window.name ?: "", index)
                includedItems[key] = true
            }
            roomQuote.floorSpaces.forEachIndexed { index, floorSpace ->
                val key = buildItemKey("floor", roomId, floorSpace.id, floorSpace.name ?: "", index)
                includedItems[key] = true
            }
        }
        renderRooms()
    }

    private fun loadRoomMeasurements(
        room: Room,
        onLoaded: (RoomQuoteData) -> Unit,
        onFailed: () -> Unit
    ) {
        val roomId = room.id ?: run {
            onFailed()
            return
        }

        Firebase.firestore.collection("windows")
            .whereEqualTo("roomId", roomId)
            .get()
            .addOnSuccessListener { windowResult ->
                val windows = windowResult.documents.mapNotNull { doc ->
                    doc.toObject<Window>()?.apply { id = doc.id }
                }

                Firebase.firestore.collection("floorspaces")
                    .whereEqualTo("roomId", roomId)
                    .get()
                    .addOnSuccessListener { floorResult ->
                        val floorSpaces = floorResult.documents.mapNotNull { doc ->
                            doc.toObject<FloorSpace>()?.apply { id = doc.id }
                        }
                        onLoaded(RoomQuoteData(room, windows, floorSpaces))
                    }
                    .addOnFailureListener {
                        Log.e(FIREBASE_TAG, "Error loading floor spaces for quote", it)
                        onLoaded(RoomQuoteData(room, windows, emptyList()))
                    }
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error loading windows for quote", it)
                onLoaded(RoomQuoteData(room, emptyList(), emptyList()))
            }
    }

    private fun renderRooms() {
        layoutQuoteContent.removeAllViews()
        lblQuoteStatus.text = if (currentUsingDefaults) getString(R.string.quote_using_defaults) else ""

        var houseTotal = 0.0

        for (roomQuote in currentRoomQuotes) {
            val roomId = roomQuote.room.id ?: continue
            val unnamed = getString(R.string.unnamed_room)
            val unnamedItem = getString(R.string.unnamed)
            val roomName = roomQuote.room.name?.ifBlank { unnamed } ?: unnamed
            val includeRoom = includedRooms[roomId] != false

            val roomToggle = CheckBox(this).apply {
                text = getString(R.string.quote_room_include_format, roomName)
                isChecked = includeRoom
                textSize = 16f
                setOnCheckedChangeListener { _, checked ->
                    includedRooms[roomId] = checked
                    renderRooms()
                }
            }
            roomToggle.layoutParams = LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
            ).apply {
                topMargin = (12 * resources.displayMetrics.density).toInt()
            }
            layoutQuoteContent.addView(roomToggle)

            var roomSubtotal = 0.0
            var hasMeasuredIncludedItem = false
            val roomTitle = makeText(
                getString(
                    R.string.quote_room_heading,
                    roomName
                ),
                18f,
                leftPaddingDp = 12,
                topMarginDp = 4
            )
            layoutQuoteContent.addView(roomTitle)

            if (!includeRoom) {
                layoutQuoteContent.addView(
                    makeText(
                        getString(R.string.quote_room_excluded),
                        14f,
                        leftPaddingDp = 12,
                        topMarginDp = 4
                    )
                )
                continue
            }

            val hasItems = roomQuote.windows.isNotEmpty() || roomQuote.floorSpaces.isNotEmpty()
            if (!hasItems) {
                layoutQuoteContent.addView(makeText(getString(R.string.quote_no_items), 14f, leftPaddingDp = 12))
            } else {
                val windowsExpanded = expandedWindowsByRoom[roomId] == true
                val floorsExpanded = expandedFloorsByRoom[roomId] == true

                roomQuote.windows.forEachIndexed { index, window ->
                    val itemKey = buildItemKey("window", roomId, window.id, window.name ?: "", index)
                    val includeItem = includedItems[itemKey] != false
                    val showItem = windowsExpanded || index < QUOTE_SECTION_PREVIEW_COUNT

                    if (showItem) {
                        layoutQuoteContent.addView(
                            makeItemToggle(
                                getString(R.string.quote_window_label),
                                window.name?.ifBlank { unnamedItem } ?: unnamedItem,
                                includeItem
                            ) { checked ->
                                includedItems[itemKey] = checked
                                renderRooms()
                            }
                        )
                    }

                    if (!includeItem) {
                        if (showItem) {
                            layoutQuoteContent.addView(
                                makeText(
                                    getString(R.string.quote_item_excluded, getString(R.string.quote_window_label)),
                                    13f,
                                    leftPaddingDp = 24,
                                    topMarginDp = 4
                                )
                            )
                        }
                        return@forEachIndexed
                    }

                    val productName = displayProductNameWithVariant(
                        window.selectedProductName,
                        window.selectedProductVariant,
                        getString(R.string.quote_product_basic_window)
                    )
                    val rate = resolveRate(window.selectedProductId, currentProductRates, DEFAULT_WINDOW_RATE)
                    val area = calculateArea(window.widthMm, window.heightMm)
                    val itemCost = area * rate
                    if (area > 0.0) {
                        hasMeasuredIncludedItem = true
                    }
                    roomSubtotal += itemCost

                    if (!showItem) {
                        return@forEachIndexed
                    }

                    layoutQuoteContent.addView(
                        makeText(
                            getString(
                                R.string.quote_window_line,
                                window.name?.ifBlank { unnamedItem } ?: unnamedItem,
                                window.widthMm,
                                window.heightMm
                            ),
                            14f,
                            leftPaddingDp = 12,
                            topMarginDp = 6
                        )
                    )
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_product_line, productName), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_area_format, area), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_rate_format, rate), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_cost_format, itemCost), 13f, leftPaddingDp = 24))
                    if (window.panelCount > 1) {
                        layoutQuoteContent.addView(makeText(getString(R.string.quote_item_panels_format, window.panelCount), 13f, leftPaddingDp = 24))
                    }
                }

                if (roomQuote.windows.size > QUOTE_SECTION_PREVIEW_COUNT) {
                    layoutQuoteContent.addView(
                        makeSectionToggleButton(
                            if (windowsExpanded) getString(R.string.quote_show_less_windows)
                            else getString(R.string.quote_show_more_windows)
                        ) {
                            expandedWindowsByRoom[roomId] = !windowsExpanded
                            renderRooms()
                        }
                    )
                }

                roomQuote.floorSpaces.forEachIndexed { index, floorSpace ->
                    val itemKey = buildItemKey("floor", roomId, floorSpace.id, floorSpace.name ?: "", index)
                    val includeItem = includedItems[itemKey] != false
                    val showItem = floorsExpanded || index < QUOTE_SECTION_PREVIEW_COUNT

                    if (showItem) {
                        layoutQuoteContent.addView(
                            makeItemToggle(
                                getString(R.string.quote_floor_label),
                                floorSpace.name?.ifBlank { unnamedItem } ?: unnamedItem,
                                includeItem
                            ) { checked ->
                                includedItems[itemKey] = checked
                                renderRooms()
                            }
                        )
                    }

                    if (!includeItem) {
                        if (showItem) {
                            layoutQuoteContent.addView(
                                makeText(
                                    getString(R.string.quote_item_excluded, getString(R.string.quote_floor_label)),
                                    13f,
                                    leftPaddingDp = 24,
                                    topMarginDp = 4
                                )
                            )
                        }
                        return@forEachIndexed
                    }

                    val productName = displayProductNameWithVariant(
                        floorSpace.selectedProductName,
                        floorSpace.selectedProductVariant,
                        getString(R.string.quote_product_basic_floor)
                    )
                    val rate = resolveRate(floorSpace.selectedProductId, currentProductRates, DEFAULT_FLOOR_RATE)
                    val area = calculateArea(floorSpace.widthMm, floorSpace.depthMm)
                    val itemCost = area * rate
                    if (area > 0.0) {
                        hasMeasuredIncludedItem = true
                    }
                    roomSubtotal += itemCost

                    if (!showItem) {
                        return@forEachIndexed
                    }

                    layoutQuoteContent.addView(
                        makeText(
                            getString(
                                R.string.quote_floor_line,
                                floorSpace.name?.ifBlank { unnamedItem } ?: unnamedItem,
                                floorSpace.widthMm,
                                floorSpace.depthMm
                            ),
                            14f,
                            leftPaddingDp = 12,
                            topMarginDp = 6
                        )
                    )
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_product_line, productName), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_area_format, area), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_rate_format, rate), 13f, leftPaddingDp = 24))
                    layoutQuoteContent.addView(makeText(getString(R.string.quote_item_cost_format, itemCost), 13f, leftPaddingDp = 24))
                }

                if (roomQuote.floorSpaces.size > QUOTE_SECTION_PREVIEW_COUNT) {
                    layoutQuoteContent.addView(
                        makeSectionToggleButton(
                            if (floorsExpanded) getString(R.string.quote_show_less_floors)
                            else getString(R.string.quote_show_more_floors)
                        ) {
                            expandedFloorsByRoom[roomId] = !floorsExpanded
                            renderRooms()
                        }
                    )
                }
            }

            val roomLabour = if (hasMeasuredIncludedItem) ROOM_LABOUR else 0.0
            val roomTotal = roomSubtotal + roomLabour
            houseTotal += roomTotal
            layoutQuoteContent.addView(makeText(getString(R.string.quote_room_subtotal_format, roomSubtotal), 14f, leftPaddingDp = 12, topMarginDp = 8))
            layoutQuoteContent.addView(makeText(getString(R.string.quote_room_labour_format, roomLabour), 14f, leftPaddingDp = 12))
            layoutQuoteContent.addView(makeText(getString(R.string.quote_room_total_format, roomTotal), 15f, leftPaddingDp = 12))
        }

        val discountAmount = houseTotal * (discountPercent / 100.0)
        val finalTotal = houseTotal - discountAmount

        lblDiscountSummary.text = if (discountPercent > 0.0) {
            getString(R.string.discount_applied_format, discountPercent, discountAmount)
        } else {
            getString(R.string.discount_none)
        }
        lblQuoteTotal.text = getString(R.string.quote_total_after_discount_format, finalTotal)
    }

    private fun shareQuoteText() {
        val sendIntent = Intent(Intent.ACTION_SEND).apply {
            type = "text/plain"
            putExtra(Intent.EXTRA_TEXT, buildShareText())
        }
        startActivity(Intent.createChooser(sendIntent, getString(R.string.share_quote_chooser)))
    }

    private fun applyDiscountFromInput() {
        val parsed = edtDiscountPercent.text?.toString()?.trim()?.toDoubleOrNull()
        if (parsed == null || parsed < 0.0 || parsed > 100.0) {
            edtDiscountPercent.error = getString(R.string.discount_invalid)
            return
        }

        edtDiscountPercent.error = null
        discountPercent = parsed
        val normalized = String.format(Locale.US, "%.1f", discountPercent)
        if (edtDiscountPercent.text?.toString() != normalized) {
            edtDiscountPercent.setText(normalized)
            edtDiscountPercent.setSelection(normalized.length)
        }
        updateDiscountButtons()
        renderRooms()
    }

    private fun clearDiscount() {
        discountPercent = 0.0
        edtDiscountPercent.setText("")
        edtDiscountPercent.error = null
        updateDiscountButtons()
        renderRooms()
    }

    private fun updateDiscountButtons() {
        val typedText = edtDiscountPercent.text?.toString()?.trim().orEmpty()
        val hasTypedValue = typedText.isNotEmpty()
        val typedValue = typedText.toDoubleOrNull()
        val hasValidValue = typedValue != null && typedValue in 0.0..100.0
        val valueChanged = hasValidValue && kotlin.math.abs((typedValue ?: 0.0) - discountPercent) > 0.0001

        btnApplyDiscount.isEnabled = hasValidValue && valueChanged
        btnClearDiscount.isEnabled = discountPercent > 0.0 || hasTypedValue
    }

    private fun buildShareText(): String {
        val titleText = lblQuoteTitle.text?.toString()?.ifBlank { getString(R.string.quote_title_default) }
            ?: getString(R.string.quote_title_default)
        val addressText = lblQuoteAddress.text?.toString()?.ifBlank { getString(R.string.quote_address_missing) }
            ?: getString(R.string.quote_address_missing)

        val summary = StringBuilder()
        summary.append(getString(R.string.quote_share_title_format, titleText)).append("\n")
        summary.append(getString(R.string.quote_share_address_format, addressText)).append("\n")

        if (currentUsingDefaults) {
            summary.append(getString(R.string.quote_using_defaults)).append("\n")
        }

        summary.append("\n")
        if (currentRoomQuotes.isEmpty()) {
            summary.append(getString(R.string.quote_no_rooms)).append("\n")
            summary.append(getString(R.string.quote_subtotal_format, 0.0)).append("\n")
            summary.append(getString(R.string.quote_discount_line_format, discountPercent, 0.0)).append("\n")
            summary.append(getString(R.string.quote_total_after_discount_format, 0.0))
            return summary.toString()
        }

        var houseTotal = 0.0
        var hasIncludedRoom = false

        for (roomQuote in currentRoomQuotes) {
            val roomId = roomQuote.room.id ?: continue
            if (includedRooms[roomId] == false) {
                continue
            }

            hasIncludedRoom = true
            val roomName = roomQuote.room.name?.ifBlank { getString(R.string.unnamed_room) } ?: getString(R.string.unnamed_room)
            summary.append(getString(R.string.quote_room_heading, roomName)).append("\n")

            var roomSubtotal = 0.0
            var hasMeasuredIncludedItem = false

            roomQuote.windows.forEachIndexed { index, window ->
                val itemKey = buildItemKey("window", roomId, window.id, window.name ?: "", index)
                if (includedItems[itemKey] == false) {
                    return@forEachIndexed
                }

                val windowName = window.name?.ifBlank { getString(R.string.unnamed) } ?: getString(R.string.unnamed)
                val productName = displayProductNameWithVariant(
                    window.selectedProductName,
                    window.selectedProductVariant,
                    getString(R.string.quote_product_basic_window)
                )
                val rate = resolveRate(window.selectedProductId, currentProductRates, DEFAULT_WINDOW_RATE)
                val area = calculateArea(window.widthMm, window.heightMm)
                val itemCost = area * rate
                if (area > 0.0) hasMeasuredIncludedItem = true
                roomSubtotal += itemCost

                summary.append("  ")
                    .append(getString(R.string.quote_window_line, windowName, window.widthMm, window.heightMm))
                    .append("\n")
                summary.append("  ")
                    .append(getString(R.string.quote_product_line, productName))
                    .append("\n")
                summary.append("  ")
                    .append(getString(R.string.quote_item_cost_format, itemCost))
                    .append("\n")
            }

            roomQuote.floorSpaces.forEachIndexed { index, floorSpace ->
                val itemKey = buildItemKey("floor", roomId, floorSpace.id, floorSpace.name ?: "", index)
                if (includedItems[itemKey] == false) {
                    return@forEachIndexed
                }

                val floorName = floorSpace.name?.ifBlank { getString(R.string.unnamed) } ?: getString(R.string.unnamed)
                val productName = displayProductNameWithVariant(
                    floorSpace.selectedProductName,
                    floorSpace.selectedProductVariant,
                    getString(R.string.quote_product_basic_floor)
                )
                val rate = resolveRate(floorSpace.selectedProductId, currentProductRates, DEFAULT_FLOOR_RATE)
                val area = calculateArea(floorSpace.widthMm, floorSpace.depthMm)
                val itemCost = area * rate
                if (area > 0.0) hasMeasuredIncludedItem = true
                roomSubtotal += itemCost

                summary.append("  ")
                    .append(getString(R.string.quote_floor_line, floorName, floorSpace.widthMm, floorSpace.depthMm))
                    .append("\n")
                summary.append("  ")
                    .append(getString(R.string.quote_product_line, productName))
                    .append("\n")
                summary.append("  ")
                    .append(getString(R.string.quote_item_cost_format, itemCost))
                    .append("\n")
            }

            val roomLabour = if (hasMeasuredIncludedItem) ROOM_LABOUR else 0.0
            val roomTotal = roomSubtotal + roomLabour
            houseTotal += roomTotal

            summary.append("  ").append(getString(R.string.quote_room_subtotal_format, roomSubtotal)).append("\n")
            summary.append("  ").append(getString(R.string.quote_room_labour_format, roomLabour)).append("\n")
            summary.append("  ").append(getString(R.string.quote_room_total_format, roomTotal)).append("\n\n")
        }

        if (!hasIncludedRoom) {
            summary.append(getString(R.string.quote_no_rooms)).append("\n")
            summary.append(getString(R.string.quote_subtotal_format, 0.0)).append("\n")
            summary.append(getString(R.string.quote_discount_line_format, discountPercent, 0.0)).append("\n")
            summary.append(getString(R.string.quote_total_after_discount_format, 0.0))
            return summary.toString()
        }

        val discountAmount = houseTotal * (discountPercent / 100.0)
        val finalTotal = houseTotal - discountAmount
        summary.append(getString(R.string.quote_subtotal_format, houseTotal)).append("\n")
        summary.append(getString(R.string.quote_discount_line_format, discountPercent, discountAmount)).append("\n")
        summary.append(getString(R.string.quote_total_after_discount_format, finalTotal))

        return summary.toString()
    }

    private fun buildItemKey(type: String, roomId: String, id: String?, fallbackName: String, index: Int): String {
        val stablePart = id ?: fallbackName
        return "$type:$roomId:$stablePart:$index"
    }

    private fun resolveRate(productId: String?, productRates: Map<String, Double>, defaultRate: Double): Double {
        if (productId.isNullOrBlank()) return defaultRate
        return productRates[productId] ?: defaultRate
    }

    private fun displayProductNameWithVariant(productName: String?, variant: String?, fallback: String): String {
        val base = productName?.takeIf { it.isNotBlank() } ?: fallback
        val selectedVariant = variant?.takeIf { it.isNotBlank() } ?: return base
        return getString(R.string.product_with_variant_format, base, selectedVariant)
    }

    private fun calculateArea(widthMm: Int, heightMm: Int): Double {
        return (widthMm / 1000.0) * (heightMm / 1000.0)
    }

    private fun parseProductRates(responseText: String): Map<String, Double> {
        val result = mutableMapOf<String, Double>()
        val array: JSONArray = if (responseText.trim().startsWith("{")) {
            val root = JSONObject(responseText)
            root.optJSONArray("data") ?: JSONArray()
        } else {
            JSONArray(responseText)
        }

        for (i in 0 until array.length()) {
            val obj = array.optJSONObject(i) ?: continue
            val id = obj.optString("id")
            if (id.isBlank()) continue
            result[id] = obj.optDouble("price_per_sqm", 0.0)
        }
        return result
    }

    private fun makeText(
        text: String,
        textSizeSp: Float,
        leftPaddingDp: Int = 0,
        topMarginDp: Int = 0
    ): TextView {
        val view = TextView(this)
        view.text = text
        view.textSize = textSizeSp

        val density = resources.displayMetrics.density
        val leftPaddingPx = (leftPaddingDp * density).toInt()
        view.setPadding(leftPaddingPx, view.paddingTop, view.paddingRight, view.paddingBottom)

        val params = LinearLayout.LayoutParams(
            ViewGroup.LayoutParams.MATCH_PARENT,
            ViewGroup.LayoutParams.WRAP_CONTENT
        )
        params.topMargin = (topMarginDp * density).toInt()
        view.layoutParams = params
        return view
    }

    private fun makeItemToggle(
        itemType: String,
        itemName: String,
        checked: Boolean,
        onChanged: (Boolean) -> Unit
    ): CheckBox {
        return CheckBox(this).apply {
            text = getString(R.string.quote_item_include_format, itemType, itemName)
            isChecked = checked
            textSize = 14f
            setPadding((12 * resources.displayMetrics.density).toInt(), paddingTop, paddingRight, paddingBottom)
            layoutParams = LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
            ).apply {
                topMargin = (6 * resources.displayMetrics.density).toInt()
            }
            setOnCheckedChangeListener { _, isChecked -> onChanged(isChecked) }
        }
    }

    private fun makeSectionToggleButton(text: String, onClick: () -> Unit): Button {
        return Button(this).apply {
            this.text = text
            layoutParams = LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
            ).apply {
                topMargin = (6 * resources.displayMetrics.density).toInt()
                marginStart = (12 * resources.displayMetrics.density).toInt()
                marginEnd = (12 * resources.displayMetrics.density).toInt()
            }
            setOnClickListener { onClick() }
        }
    }
}

package au.edu.utas.kit305.tutorial05

import android.Manifest
import android.app.AlertDialog
import android.content.Intent
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.graphics.BitmapFactory
import android.net.Uri
import android.os.Bundle
import android.util.Base64
import android.util.Log
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Button
import android.widget.EditText
import android.widget.ImageView
import android.widget.LinearLayout
import android.widget.TextView
import android.widget.Toast
import androidx.core.widget.doAfterTextChanged
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import com.google.firebase.ktx.Firebase
import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.firestore.toObject
import java.io.ByteArrayOutputStream
import java.io.File
import java.net.URL
import kotlin.math.roundToInt

const val ROOM_INDEX           = "Room_Index"
const val HOUSE_ID_EXTRA       = "House_Id"
const val WINDOW_ID_EXTRA      = "window_id"
const val FLOOR_SPACE_ID_EXTRA = "floor_space_id"

class RoomDetails : AppCompatActivity() {

    private enum class PhotoTarget {
        ROOM,
        WINDOW,
        FLOOR_SPACE
    }

    private lateinit var txtRoomName:         android.widget.EditText
    private lateinit var lblRoomTitle:        android.widget.TextView
    private lateinit var btnSaveRoom:         android.widget.Button
    private lateinit var lstWindows:          RecyclerView
    private lateinit var lstFloorSpaces:      RecyclerView
    private lateinit var btnAddWindow:        android.widget.Button
    private lateinit var btnAddFloorSpace:    android.widget.Button
    private lateinit var btnToggleWindows:    android.widget.Button
    private lateinit var btnToggleFloor:      android.widget.Button
    private lateinit var txtSearchWindows:    EditText
    private lateinit var txtSearchFloor:      EditText
    private lateinit var lblWindowCount:      android.widget.TextView
    private lateinit var lblFloorSpaceCount:  android.widget.TextView
    private lateinit var imgRoom:             ImageView
    private lateinit var btnTakePhoto:        android.widget.Button
    private lateinit var btnPickGallery:      android.widget.Button
    private lateinit var btnRemoveRoomPhoto:  android.widget.Button

    private val windowList     = mutableListOf<Window>()
    private val floorSpaceList = mutableListOf<FloorSpace>()
    private val filteredWindowList = mutableListOf<Window>()
    private val filteredFloorSpaceList = mutableListOf<FloorSpace>()
    private var windowsExpanded = false
    private var floorSpacesExpanded = false
    private var windowsSearchQuery = ""
    private var floorSearchQuery = ""

    private var pendingWindowId: String? = null
    private var pendingFloorSpaceId: String? = null
    private lateinit var roomId: String
    private var pendingCameraUri: Uri? = null
    private var currentPhotoTarget: PhotoTarget = PhotoTarget.ROOM
    private var currentPhotoItemPos: Int = -1

    private lateinit var windowsAdapter: MeasurementAdapter<Window>
    private lateinit var floorAdapter: MeasurementAdapter<FloorSpace>

    // ─── Activity Result Launchers ───────────────────────────────────────────

    private val windowProductLauncher: ActivityResultLauncher<Intent> =
        registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            if (result.resultCode == RESULT_OK && !pendingWindowId.isNullOrBlank()) {
                val productId = result.data?.getStringExtra(RESULT_PRODUCT_ID) ?: ""
                val productName = result.data?.getStringExtra(RESULT_PRODUCT_NAME) ?: ""
                val panelCount = result.data?.getIntExtra(RESULT_PANEL_COUNT, 1) ?: 1
                if (productId.isNotBlank()) saveWindowProductById(pendingWindowId!!, productId, productName, panelCount)
            }
            pendingWindowId = null
        }

    private val floorProductLauncher: ActivityResultLauncher<Intent> =
        registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            if (result.resultCode == RESULT_OK && !pendingFloorSpaceId.isNullOrBlank()) {
                val productId = result.data?.getStringExtra(RESULT_PRODUCT_ID) ?: ""
                val productName = result.data?.getStringExtra(RESULT_PRODUCT_NAME) ?: ""
                if (productId.isNotBlank()) saveFloorSpaceProductById(pendingFloorSpaceId!!, productId, productName)
            }
            pendingFloorSpaceId = null
        }

    private val cameraPermissionLauncher =
        registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
            if (granted) {
                launchCameraCapture()
            } else {
                Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show()
            }
        }

    private val takePictureLauncher =
        registerForActivityResult(ActivityResultContracts.TakePicture()) { success ->
            val uri = pendingCameraUri
            if (success && uri != null) {
                handleSelectedPhoto(uri)
            }
            pendingCameraUri = null
        }

    private val pickImageLauncher =
        registerForActivityResult(ActivityResultContracts.GetContent()) { uri ->
            if (uri != null) {
                handleSelectedPhoto(uri)
            }
        }

    // ─── Lifecycle ───────────────────────────────────────────────────────────

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_room_details)

        txtRoomName        = findViewById(R.id.txtRoomName)
        lblRoomTitle       = findViewById(R.id.lblRoomTitle)
        btnSaveRoom        = findViewById(R.id.btnSaveRoom)
        lstWindows         = findViewById(R.id.lstWindows)
        lstFloorSpaces     = findViewById(R.id.lstFloorSpaces)
        btnAddWindow       = findViewById(R.id.btnAddWindow)
        btnAddFloorSpace   = findViewById(R.id.btnAddFloorSpace)
        btnToggleWindows   = findViewById(R.id.btnToggleWindows)
        btnToggleFloor     = findViewById(R.id.btnToggleFloorSpaces)
        txtSearchWindows   = findViewById(R.id.txtSearchWindows)
        txtSearchFloor     = findViewById(R.id.txtSearchFloorSpaces)
        lblWindowCount     = findViewById(R.id.lblWindowCount)
        lblFloorSpaceCount = findViewById(R.id.lblFloorSpaceCount)
        imgRoom            = findViewById(R.id.imgRoom)
        btnTakePhoto       = findViewById(R.id.btnTakePhoto)
        btnPickGallery     = findViewById(R.id.btnPickGallery)
        btnRemoveRoomPhoto = findViewById(R.id.btnRemoveRoomPhoto)
        btnRemoveRoomPhoto.visibility = View.GONE

        roomId = intent.getStringExtra("room_id") ?: run { finish(); return }
        val roomName = intent.getStringExtra("room_name") ?: ""

        txtRoomName.setText(roomName)
        lblRoomTitle.text = roomName
        loadRoom(roomId)

        lstWindows.layoutManager = LinearLayoutManager(this)
        windowsAdapter = MeasurementAdapter(
            items           = filteredWindowList,
            nameFn          = { w -> w.name ?: "Unnamed" },
            dimsFn          = { w -> "${w.widthMm}mm × ${w.heightMm}mm" },
            productFn       = { w -> w.selectedProductName },
            photoFn         = { w -> w.photoBase64 },
            onEdit          = { pos -> openWindowEdit(pos) },
            onDelete        = { pos -> deleteWindow(pos) },
            onSelectProduct = { pos -> launchWindowProductPicker(pos) },
            onPhoto         = { pos -> startMeasurementCamera(PhotoTarget.WINDOW, pos) },
            onGallery       = { pos -> startMeasurementGallery(PhotoTarget.WINDOW, pos) },
            onRemovePhoto   = { pos -> promptRemovePhoto(PhotoTarget.WINDOW, pos) }
        )
        lstWindows.adapter = windowsAdapter

        lstFloorSpaces.layoutManager = LinearLayoutManager(this)
        floorAdapter = MeasurementAdapter(
            items           = filteredFloorSpaceList,
            nameFn          = { f -> f.name ?: "Unnamed" },
            dimsFn          = { f -> "${f.widthMm}mm × ${f.depthMm}mm" },
            productFn       = { f -> f.selectedProductName },
            photoFn         = { f -> f.photoBase64 },
            onEdit          = { pos -> openFloorSpaceEdit(pos) },
            onDelete        = { pos -> deleteFloorSpace(pos) },
            onSelectProduct = { pos -> launchFloorProductPicker(pos) },
            onPhoto         = { pos -> startMeasurementCamera(PhotoTarget.FLOOR_SPACE, pos) },
            onGallery       = { pos -> startMeasurementGallery(PhotoTarget.FLOOR_SPACE, pos) },
            onRemovePhoto   = { pos -> promptRemovePhoto(PhotoTarget.FLOOR_SPACE, pos) }
        )
        lstFloorSpaces.adapter = floorAdapter

        btnToggleWindows.setOnClickListener {
            windowsExpanded = !windowsExpanded
            windowsAdapter.setExpanded(windowsExpanded)
            lstWindows.post { lstWindows.requestLayout() }
            updateToggleButtons()
        }

        btnToggleFloor.setOnClickListener {
            floorSpacesExpanded = !floorSpacesExpanded
            floorAdapter.setExpanded(floorSpacesExpanded)
            lstFloorSpaces.post { lstFloorSpaces.requestLayout() }
            updateToggleButtons()
        }

        txtSearchWindows.doAfterTextChanged {
            windowsSearchQuery = it?.toString()?.trim().orEmpty()
            applyWindowFilter()
        }

        txtSearchFloor.doAfterTextChanged {
            floorSearchQuery = it?.toString()?.trim().orEmpty()
            applyFloorFilter()
        }

        loadWindows(roomId)
        loadFloorSpaces(roomId)

        btnAddWindow.setOnClickListener     { addWindow(roomId) }
        btnAddFloorSpace.setOnClickListener { addFloorSpace(roomId) }
        btnTakePhoto.setOnClickListener {
            setPhotoTarget(PhotoTarget.ROOM)
            requestCameraPermissionAndCapture()
        }
        btnPickGallery.setOnClickListener {
            setPhotoTarget(PhotoTarget.ROOM)
            pickImageLauncher.launch("image/*")
        }
        btnRemoveRoomPhoto.setOnClickListener {
            promptRemovePhoto(PhotoTarget.ROOM, -1)
        }

        btnSaveRoom.setOnClickListener {
            val name = txtRoomName.text.toString().trim()
            if (name.isBlank()) { lblRoomTitle.text = "Room name cannot be empty"; return@setOnClickListener }
            Firebase.firestore.collection("rooms").document(roomId)
                .update("name", name)
                .addOnSuccessListener { Log.d(FIREBASE_TAG, "Room updated"); finish() }
                .addOnFailureListener { Log.e(FIREBASE_TAG, "Error updating room", it); lblRoomTitle.text = "Could not save room" }
        }
    }

    private fun loadRoom(roomId: String) {
        Firebase.firestore.collection("rooms").document(roomId).get()
            .addOnSuccessListener { doc ->
                val room = doc.toObject<Room>() ?: return@addOnSuccessListener
                txtRoomName.setText(room.name ?: "")
                lblRoomTitle.text = room.name ?: "Room"
                showRoomPhoto(room.photoBase64, room.photoUrl)
            }
            .addOnFailureListener { Log.e(FIREBASE_TAG, "Error loading room", it) }
    }

    private fun requestCameraPermissionAndCapture() {
        val granted = ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED
        if (granted) {
            launchCameraCapture()
        } else {
            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        }
    }

    private fun launchCameraCapture() {
        val uri = createTempImageUri() ?: run {
            Toast.makeText(this, "Could not prepare camera file", Toast.LENGTH_SHORT).show()
            return
        }
        pendingCameraUri = uri
        takePictureLauncher.launch(uri)
    }

    private fun setPhotoTarget(target: PhotoTarget, itemPos: Int = -1) {
        currentPhotoTarget = target
        currentPhotoItemPos = itemPos
    }

    private fun startMeasurementCamera(target: PhotoTarget, pos: Int) {
        setPhotoTarget(target, pos)
        requestCameraPermissionAndCapture()
    }

    private fun startMeasurementGallery(target: PhotoTarget, pos: Int) {
        setPhotoTarget(target, pos)
        pickImageLauncher.launch("image/*")
    }

    private fun handleSelectedPhoto(uri: Uri) {
        when (currentPhotoTarget) {
            PhotoTarget.ROOM -> {
                imgRoom.visibility = View.VISIBLE
                imgRoom.setImageURI(uri)
                uploadRoomPhoto(uri)
            }
            PhotoTarget.WINDOW -> saveWindowPhoto(currentPhotoItemPos, uri)
            PhotoTarget.FLOOR_SPACE -> saveFloorSpacePhoto(currentPhotoItemPos, uri)
        }
    }

    private fun createTempImageUri(): Uri? {
        return try {
            val imageDir = File(cacheDir, "room_photos").apply { mkdirs() }
            val imageFile = File.createTempFile("room_${roomId}_", ".jpg", imageDir)
            FileProvider.getUriForFile(this, "${applicationContext.packageName}.fileprovider", imageFile)
        } catch (e: Exception) {
            Log.e(FIREBASE_TAG, "Error creating temp image uri", e)
            null
        }
    }

    private fun uploadRoomPhoto(uri: Uri) {
        val base64 = encodeImageToBase64(uri)
        if (base64 == null) {
            Toast.makeText(this, "Photo processing failed", Toast.LENGTH_SHORT).show()
            return
        }

        Firebase.firestore.collection("rooms").document(roomId)
            .update(mapOf("photoBase64" to base64, "photoUrl" to ""))
            .addOnSuccessListener {
                Toast.makeText(this, "Room photo saved", Toast.LENGTH_SHORT).show()
                showRoomPhoto(base64, null)
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error saving photo in Firestore", it)
                Toast.makeText(this, "Photo save failed: ${it.message ?: "unknown"}", Toast.LENGTH_LONG).show()
            }
    }

    private fun saveWindowPhoto(pos: Int, uri: Uri) {
        if (pos !in filteredWindowList.indices) return
        val base64 = encodeImageToBase64(uri) ?: run {
            Toast.makeText(this, "Photo processing failed", Toast.LENGTH_SHORT).show()
            return
        }
        val window = filteredWindowList[pos]
        val windowId = window.id ?: return

        Firebase.firestore.collection("windows").document(windowId)
            .update("photoBase64", base64)
            .addOnSuccessListener {
                window.photoBase64 = base64
                applyWindowFilter()
                Toast.makeText(this, "Window photo saved", Toast.LENGTH_SHORT).show()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error saving window photo", it)
                Toast.makeText(this, "Window photo save failed", Toast.LENGTH_SHORT).show()
            }
    }

    private fun saveFloorSpacePhoto(pos: Int, uri: Uri) {
        if (pos !in filteredFloorSpaceList.indices) return
        val base64 = encodeImageToBase64(uri) ?: run {
            Toast.makeText(this, "Photo processing failed", Toast.LENGTH_SHORT).show()
            return
        }
        val floorSpace = filteredFloorSpaceList[pos]
        val floorSpaceId = floorSpace.id ?: return

        Firebase.firestore.collection("floorspaces").document(floorSpaceId)
            .update("photoBase64", base64)
            .addOnSuccessListener {
                floorSpace.photoBase64 = base64
                applyFloorFilter()
                Toast.makeText(this, "Floor photo saved", Toast.LENGTH_SHORT).show()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error saving floor photo", it)
                Toast.makeText(this, "Floor photo save failed", Toast.LENGTH_SHORT).show()
            }
    }

    private fun removeMeasurementPhoto(target: PhotoTarget, pos: Int) {
        when (target) {
            PhotoTarget.ROOM -> {
                Firebase.firestore.collection("rooms").document(roomId)
                    .update(mapOf("photoBase64" to "", "photoUrl" to ""))
                    .addOnSuccessListener {
                        imgRoom.setImageDrawable(null)
                        imgRoom.visibility = View.GONE
                        btnRemoveRoomPhoto.visibility = View.GONE
                    }
                return
            }
            PhotoTarget.WINDOW -> {
                if (pos !in filteredWindowList.indices) return
                val item = filteredWindowList[pos]
                val itemId = item.id ?: return
                Firebase.firestore.collection("windows").document(itemId)
                    .update("photoBase64", "")
                    .addOnSuccessListener {
                        item.photoBase64 = null
                        applyWindowFilter()
                    }
                    .addOnFailureListener { Log.e(FIREBASE_TAG, "Error removing window photo", it) }
            }
            PhotoTarget.FLOOR_SPACE -> {
                if (pos !in filteredFloorSpaceList.indices) return
                val item = filteredFloorSpaceList[pos]
                val itemId = item.id ?: return
                Firebase.firestore.collection("floorspaces").document(itemId)
                    .update("photoBase64", "")
                    .addOnSuccessListener {
                        item.photoBase64 = null
                        applyFloorFilter()
                    }
                    .addOnFailureListener { Log.e(FIREBASE_TAG, "Error removing floor photo", it) }
            }
        }
    }

    private fun promptRemovePhoto(target: PhotoTarget, pos: Int) {
        val message = when (target) {
            PhotoTarget.ROOM -> "Remove room photo?"
            PhotoTarget.WINDOW -> "Remove this window photo?"
            PhotoTarget.FLOOR_SPACE -> "Remove this floor space photo?"
        }

        AlertDialog.Builder(this)
            .setMessage(message)
            .setPositiveButton("Remove") { _, _ -> removeMeasurementPhoto(target, pos) }
            .setNegativeButton("Cancel", null)
            .show()
    }

    private fun encodeImageToBase64(uri: Uri): String? {
        return try {
            val bitmap = contentResolver.openInputStream(uri)?.use { BitmapFactory.decodeStream(it) } ?: return null
            val bytes = compressBitmap(bitmap)
            Base64.encodeToString(bytes, Base64.DEFAULT)
        } catch (e: Exception) {
            Log.e(FIREBASE_TAG, "Error encoding photo", e)
            null
        }
    }

    private fun compressBitmap(bitmap: Bitmap): ByteArray {
        val scaledBitmap = scaleBitmap(bitmap, 1280)
        val output = ByteArrayOutputStream()
        var quality = 85
        scaledBitmap.compress(Bitmap.CompressFormat.JPEG, quality, output)

        // Keep comfortably under Firestore doc size constraints after Base64 expansion.
        while (output.size() > 250_000 && quality > 25) {
            output.reset()
            quality -= 10
            scaledBitmap.compress(Bitmap.CompressFormat.JPEG, quality, output)
        }
        return output.toByteArray()
    }

    private fun scaleBitmap(bitmap: Bitmap, maxDimension: Int): Bitmap {
        val largestSide = maxOf(bitmap.width, bitmap.height)
        if (largestSide <= maxDimension) return bitmap

        val scale = maxDimension.toFloat() / largestSide.toFloat()
        val width = (bitmap.width * scale).roundToInt()
        val height = (bitmap.height * scale).roundToInt()
        return Bitmap.createScaledBitmap(bitmap, width, height, true)
    }

    private fun showRoomPhoto(photoBase64: String?, photoUrl: String?) {
        if (!photoBase64.isNullOrBlank()) {
            try {
                val bytes = Base64.decode(photoBase64, Base64.DEFAULT)
                val bitmap = BitmapFactory.decodeByteArray(bytes, 0, bytes.size)
                if (bitmap != null) {
                    imgRoom.setImageBitmap(bitmap)
                    imgRoom.visibility = View.VISIBLE
                    btnRemoveRoomPhoto.visibility = View.VISIBLE
                    return
                }
            } catch (e: Exception) {
                Log.e(FIREBASE_TAG, "Error decoding base64 room photo", e)
            }
        }

        if (photoUrl.isNullOrBlank()) {
            imgRoom.setImageDrawable(null)
            imgRoom.visibility = View.GONE
            btnRemoveRoomPhoto.visibility = View.GONE
            return
        }

        imgRoom.visibility = View.VISIBLE
        Thread {
            try {
                val bitmap = URL(photoUrl).openStream().use { BitmapFactory.decodeStream(it) }
                runOnUiThread {
                    if (bitmap != null) {
                        imgRoom.setImageBitmap(bitmap)
                        btnRemoveRoomPhoto.visibility = View.VISIBLE
                    } else {
                        imgRoom.setImageDrawable(null)
                        imgRoom.visibility = View.GONE
                        btnRemoveRoomPhoto.visibility = View.GONE
                    }
                }
            } catch (e: Exception) {
                Log.e(FIREBASE_TAG, "Error loading room photo", e)
                runOnUiThread {
                    imgRoom.setImageDrawable(null)
                    imgRoom.visibility = View.GONE
                    btnRemoveRoomPhoto.visibility = View.GONE
                }
            }
        }.start()
    }

    // ─── Windows ─────────────────────────────────────────────────────────────

    private fun loadWindows(roomId: String) {
        Firebase.firestore.collection("windows").whereEqualTo("roomId", roomId).get()
            .addOnSuccessListener { result ->
                windowList.clear()
                for (doc in result) { val w = doc.toObject<Window>(); w.id = doc.id; windowList.add(w) }
                lblWindowCount.text = "${windowList.size} Windows"
                // Keep adapter/toggle state in sync with the currently filtered list.
                applyWindowFilter()
            }
            .addOnFailureListener { Log.e(FIREBASE_TAG, "Error loading windows", it) }
    }

    private fun addWindow(roomId: String) {
        showMeasurementDialog(
            "Add Window",
            "New Window",
            "Width (mm)",
            0,
            "Height (mm)",
            0
        ) { name, d1, d2 ->
            val w = Window(roomId = roomId, name = name, widthMm = d1, heightMm = d2)
            Firebase.firestore.collection("windows").add(w)
                .addOnSuccessListener {
                    w.id = it.id
                    windowList.add(0, w)
                    lblWindowCount.text = "${windowList.size} Windows"
                    lstWindows.scrollToPosition(0)
                    applyWindowFilter()
                }
                .addOnFailureListener { Log.e(FIREBASE_TAG, "Error adding window", it) }
        }
    }

    private fun deleteWindow(pos: Int) {
        if (pos !in filteredWindowList.indices) return
        val w = filteredWindowList[pos]
        val wId = w.id ?: return
        AlertDialog.Builder(this).setMessage("Delete this window?")
            .setPositiveButton("Delete") { _, _ ->
                Firebase.firestore.collection("windows").document(wId).delete()
                    .addOnSuccessListener {
                        windowList.removeAll { it.id == wId }
                        if (windowList.size <= 2) windowsExpanded = false
                        windowsAdapter.setExpanded(windowsExpanded)
                        lblWindowCount.text = "${windowList.size} Windows"
                        applyWindowFilter()
                    }
                    .addOnFailureListener { Log.e(FIREBASE_TAG, "Error deleting window", it) }
            }.setNegativeButton("Cancel", null).show()
    }

    private fun openWindowEdit(pos: Int) {
        if (pos < 0 || pos >= filteredWindowList.size) return
        val w = filteredWindowList[pos]; val wId = w.id ?: return
        showMeasurementDialog("Edit Window", w.name ?: "", "Width (mm)", w.widthMm, "Height (mm)", w.heightMm) { name, d1, d2 ->
            Firebase.firestore.collection("windows").document(wId).update(mapOf("name" to name, "widthMm" to d1, "heightMm" to d2))
                .addOnSuccessListener { w.name = name; w.widthMm = d1; w.heightMm = d2; applyWindowFilter() }
                .addOnFailureListener { Log.e(FIREBASE_TAG, "Error updating window", it) }
        }
    }

    private fun launchWindowProductPicker(pos: Int) {
        if (pos < 0 || pos >= filteredWindowList.size) return
        val w = filteredWindowList[pos]
        pendingWindowId = w.id
        val i = Intent(this, ProductListActivity::class.java)
            .putExtra(EXTRA_PRODUCT_TYPE, "window")
            .putExtra(EXTRA_SPACE_WIDTH,  w.widthMm)
            .putExtra(EXTRA_SPACE_HEIGHT, w.heightMm)
        windowProductLauncher.launch(i)
    }

    private fun saveWindowProductById(windowId: String, productId: String, productName: String, panelCount: Int) {
        val w = windowList.firstOrNull { it.id == windowId } ?: return
        val wId = w.id ?: return
        Firebase.firestore.collection("windows").document(wId)
            .update(mapOf("selectedProductId" to productId, "selectedProductName" to productName, "panelCount" to panelCount))
            .addOnSuccessListener {
                w.selectedProductId = productId; w.selectedProductName = productName; w.panelCount = panelCount
                applyWindowFilter()
                Log.d(FIREBASE_TAG, "Window product saved: $productName x$panelCount panels")
            }
            .addOnFailureListener { Log.e(FIREBASE_TAG, "Error saving window product", it) }
    }

    // ─── Floor Spaces ────────────────────────────────────────────────────────

    private fun loadFloorSpaces(roomId: String) {
        Firebase.firestore.collection("floorspaces").whereEqualTo("roomId", roomId).get()
            .addOnSuccessListener { result ->
                floorSpaceList.clear()
                for (doc in result) { val f = doc.toObject<FloorSpace>(); f.id = doc.id; floorSpaceList.add(f) }
                lblFloorSpaceCount.text = "${floorSpaceList.size} Floor Spaces"
                applyFloorFilter()
            }
            .addOnFailureListener { Log.e(FIREBASE_TAG, "Error loading floor spaces", it) }
    }

    private fun addFloorSpace(roomId: String) {
        showMeasurementDialog(
            "Add Floor Space",
            "New Floor Space",
            "Width (mm)",
            0,
            "Depth (mm)",
            0
        ) { name, d1, d2 ->
            val f = FloorSpace(roomId = roomId, name = name, widthMm = d1, depthMm = d2)
            Firebase.firestore.collection("floorspaces").add(f)
                .addOnSuccessListener {
                    f.id = it.id
                    floorSpaceList.add(0, f)
                    lblFloorSpaceCount.text = "${floorSpaceList.size} Floor Spaces"
                    lstFloorSpaces.scrollToPosition(0)
                    applyFloorFilter()
                }
                .addOnFailureListener { Log.e(FIREBASE_TAG, "Error adding floor space", it) }
        }
    }

    private fun deleteFloorSpace(pos: Int) {
        if (pos !in filteredFloorSpaceList.indices) return
        val f = filteredFloorSpaceList[pos]
        val fId = f.id ?: return
        AlertDialog.Builder(this).setMessage("Delete this floor space?")
            .setPositiveButton("Delete") { _, _ ->
                Firebase.firestore.collection("floorspaces").document(fId).delete()
                    .addOnSuccessListener {
                        floorSpaceList.removeAll { it.id == fId }
                        if (floorSpaceList.size <= 2) floorSpacesExpanded = false
                        floorAdapter.setExpanded(floorSpacesExpanded)
                        lblFloorSpaceCount.text = "${floorSpaceList.size} Floor Spaces"
                        applyFloorFilter()
                    }
                    .addOnFailureListener { Log.e(FIREBASE_TAG, "Error deleting floor space", it) }
            }.setNegativeButton("Cancel", null).show()
    }

    private fun openFloorSpaceEdit(pos: Int) {
        if (pos < 0 || pos >= filteredFloorSpaceList.size) return
        val f = filteredFloorSpaceList[pos]; val fId = f.id ?: return
        showMeasurementDialog("Edit Floor Space", f.name ?: "", "Width (mm)", f.widthMm, "Depth (mm)", f.depthMm) { name, d1, d2 ->
            Firebase.firestore.collection("floorspaces").document(fId).update(mapOf("name" to name, "widthMm" to d1, "depthMm" to d2))
                .addOnSuccessListener { f.name = name; f.widthMm = d1; f.depthMm = d2; applyFloorFilter() }
                .addOnFailureListener { Log.e(FIREBASE_TAG, "Error updating floor space", it) }
        }
    }

    private fun launchFloorProductPicker(pos: Int) {
        if (pos < 0 || pos >= filteredFloorSpaceList.size) return
        val f = filteredFloorSpaceList[pos]
        pendingFloorSpaceId = f.id
        val i = Intent(this, ProductListActivity::class.java)
            .putExtra(EXTRA_PRODUCT_TYPE, "floor")
            .putExtra(EXTRA_SPACE_WIDTH,  f.widthMm)
            .putExtra(EXTRA_SPACE_HEIGHT, f.depthMm)
        floorProductLauncher.launch(i)
    }

    private fun saveFloorSpaceProductById(floorId: String, productId: String, productName: String) {
        val f = floorSpaceList.firstOrNull { it.id == floorId } ?: return
        val fId = f.id ?: return
        Firebase.firestore.collection("floorspaces").document(fId)
            .update(mapOf("selectedProductId" to productId, "selectedProductName" to productName))
            .addOnSuccessListener {
                f.selectedProductId = productId; f.selectedProductName = productName
                applyFloorFilter()
                Log.d(FIREBASE_TAG, "FloorSpace product saved: $productName")
            }
            .addOnFailureListener { Log.e(FIREBASE_TAG, "Error saving floor space product", it) }
    }

    // ─── Shared dialog ────────────────────────────────────────────────────────

    private fun showMeasurementDialog(
        title: String, name: String,
        dim1Label: String, dim1Value: Int,
        dim2Label: String, dim2Value: Int,
        onSave: (String, Int, Int) -> Unit
    ) {
        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            val p = (16 * resources.displayMetrics.density).toInt()
            setPadding(p, p, p, 0)
        }
        fun et(hint: String, value: String, numeric: Boolean) = EditText(this).apply {
            this.hint = hint; setText(value)
            if (numeric) inputType = android.text.InputType.TYPE_CLASS_NUMBER
        }
        val etName = et("Name", name, false)
        val etD1   = et(dim1Label, if (dim1Value > 0) dim1Value.toString() else "", true)
        val etD2   = et(dim2Label, if (dim2Value > 0) dim2Value.toString() else "", true)
        layout.addView(etName); layout.addView(etD1); layout.addView(etD2)

        AlertDialog.Builder(this).setTitle(title).setView(layout)
            .setPositiveButton("Save") { _, _ ->
                onSave(
                    etName.text.toString().trim().ifBlank { "Unnamed" },
                    etD1.text.toString().toIntOrNull() ?: 0,
                    etD2.text.toString().toIntOrNull() ?: 0
                )
            }
            .setNegativeButton("Cancel", null).show()
    }

    private fun updateToggleButtons() {
        // Keep toggle available based on total list size (not search result size)
        // so users can always expand/collapse the main list clearly.
        btnToggleWindows.visibility = if (windowList.size > 2) View.VISIBLE else View.GONE
        btnToggleWindows.text = if (windowsExpanded) "Show Less Windows" else "Show More Windows"

        btnToggleFloor.visibility = if (floorSpaceList.size > 2) View.VISIBLE else View.GONE
        btnToggleFloor.text = if (floorSpacesExpanded) "Show Less Floor Spaces" else "Show More Floor Spaces"
    }

    private fun applyWindowFilter() {
        val q = windowsSearchQuery.lowercase()
        filteredWindowList.clear()
        if (q.isBlank()) {
            filteredWindowList.addAll(windowList)
        } else {
            filteredWindowList.addAll(
                windowList.filter {
                    val name = it.name.orEmpty().lowercase()
                    val product = it.selectedProductName.orEmpty().lowercase()
                    name.contains(q) || product.contains(q)
                }
            )
        }

        if (filteredWindowList.size <= 2) windowsExpanded = false
        windowsAdapter.setExpanded(windowsExpanded)
        lstWindows.post { lstWindows.requestLayout() }
        updateToggleButtons()
    }

    private fun applyFloorFilter() {
        val q = floorSearchQuery.lowercase()
        filteredFloorSpaceList.clear()
        if (q.isBlank()) {
            filteredFloorSpaceList.addAll(floorSpaceList)
        } else {
            filteredFloorSpaceList.addAll(
                floorSpaceList.filter {
                    val name = it.name.orEmpty().lowercase()
                    val product = it.selectedProductName.orEmpty().lowercase()
                    name.contains(q) || product.contains(q)
                }
            )
        }

        if (filteredFloorSpaceList.size <= 2) floorSpacesExpanded = false
        floorAdapter.setExpanded(floorSpacesExpanded)
        lstFloorSpaces.post { lstFloorSpaces.requestLayout() }
        updateToggleButtons()
    }

    // ─── Adapter ─────────────────────────────────────────────────────────────

    class MeasurementHolder(val root: android.view.View) : RecyclerView.ViewHolder(root) {
        val txtName:    TextView = root.findViewById(R.id.txtMeasurementName)
        val txtDims:    TextView = root.findViewById(R.id.txtMeasurementDims)
        val txtProduct: TextView = root.findViewById(R.id.txtSelectedProduct)
        val imgPhoto:   ImageView = root.findViewById(R.id.imgMeasurementPhoto)
        val btnEdit:    Button   = root.findViewById(R.id.btnMeasurementEdit)
        val btnDelete:  Button   = root.findViewById(R.id.btnMeasurementDelete)
        val btnProduct: Button   = root.findViewById(R.id.btnSelectProduct)
        val btnPhoto:   Button   = root.findViewById(R.id.btnMeasurementPhoto)
        val btnGallery: Button = root.findViewById(R.id.btnMeasurementGallery)
        val btnRemovePhoto: Button = root.findViewById(R.id.btnMeasurementRemovePhoto)
    }

    class MeasurementAdapter<T>(
        private val items:           MutableList<T>,
        private val nameFn:          (T) -> String,
        private val dimsFn:          (T) -> String,
        private val productFn:       (T) -> String?,
        private val photoFn:         (T) -> String?,
        private val onEdit:          (Int) -> Unit,
        private val onDelete:        (Int) -> Unit,
        private val onSelectProduct: (Int) -> Unit,
        private val onPhoto:         (Int) -> Unit,
        private val onGallery:       (Int) -> Unit,
        private val onRemovePhoto:   (Int) -> Unit
    ) : RecyclerView.Adapter<MeasurementHolder>() {

        private var isExpanded = false
        private val itemsPerPage = 2

        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): MeasurementHolder {
            val v = LayoutInflater.from(parent.context)
                .inflate(R.layout.measurement_list_item, parent, false)
            return MeasurementHolder(v)
        }

        override fun getItemCount(): Int {
            return if (isExpanded) items.size else minOf(itemsPerPage, items.size)
        }

        override fun onBindViewHolder(holder: MeasurementHolder, position: Int) {
            val item = items[position]
            holder.txtName.text = nameFn(item)
            holder.txtDims.text = dimsFn(item)
            val prod = productFn(item)
            holder.txtProduct.text = if (!prod.isNullOrBlank()) "Product: $prod" else "No product selected"
            bindPhoto(holder.imgPhoto, holder.btnRemovePhoto, photoFn(item))

            holder.root.setOnClickListener {
                val p = holder.bindingAdapterPosition
                if (p != RecyclerView.NO_POSITION) onEdit(p)
            }

            holder.btnEdit.setOnClickListener { val p = holder.bindingAdapterPosition; if (p != RecyclerView.NO_POSITION) onEdit(p) }
            holder.btnDelete.setOnClickListener { val p = holder.bindingAdapterPosition; if (p != RecyclerView.NO_POSITION) onDelete(p) }
            holder.btnProduct.setOnClickListener { val p = holder.bindingAdapterPosition; if (p != RecyclerView.NO_POSITION) onSelectProduct(p) }
            holder.btnPhoto.setOnClickListener { val p = holder.bindingAdapterPosition; if (p != RecyclerView.NO_POSITION) onPhoto(p) }
            holder.btnGallery.setOnClickListener { val p = holder.bindingAdapterPosition; if (p != RecyclerView.NO_POSITION) onGallery(p) }
            holder.btnRemovePhoto.setOnClickListener { val p = holder.bindingAdapterPosition; if (p != RecyclerView.NO_POSITION) onRemovePhoto(p) }
        }

        fun setExpanded(expanded: Boolean) {
            isExpanded = expanded
            notifyDataSetChanged()
        }

        private fun bindPhoto(imageView: ImageView, removeButton: Button, photoBase64: String?) {
            if (photoBase64.isNullOrBlank()) {
                imageView.setImageDrawable(null)
                imageView.visibility = View.GONE
                removeButton.visibility = View.GONE
                return
            }

            try {
                val bytes = Base64.decode(photoBase64, Base64.DEFAULT)
                val bitmap = BitmapFactory.decodeByteArray(bytes, 0, bytes.size)
                if (bitmap != null) {
                    imageView.setImageBitmap(bitmap)
                    imageView.visibility = View.VISIBLE
                    removeButton.visibility = View.VISIBLE
                } else {
                    imageView.setImageDrawable(null)
                    imageView.visibility = View.GONE
                    removeButton.visibility = View.GONE
                }
            } catch (_: Exception) {
                imageView.setImageDrawable(null)
                imageView.visibility = View.GONE
                removeButton.visibility = View.GONE
            }
        }
    }

}

package au.edu.utas.kit305.tutorial05

import android.Manifest
import android.app.AlertDialog
import android.content.Intent
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.graphics.BitmapFactory
import android.net.Uri
import android.os.Bundle
import android.util.Base64
import android.util.Log
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.text.InputFilter
import android.text.InputType
import android.text.method.DigitsKeyListener
import android.widget.Button
import android.widget.EditText
import android.widget.ImageView
import android.widget.LinearLayout
import android.widget.TextView
import android.widget.Toast
import androidx.core.widget.doAfterTextChanged
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import com.google.firebase.ktx.Firebase
import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.firestore.toObject
import androidx.core.graphics.scale
import java.io.File
import java.io.ByteArrayOutputStream
import kotlin.math.roundToInt

const val HOUSE_ID_EXTRA       = "House_Id"

class RoomDetails : AppCompatActivity() {

    companion object {
        private const val MIN_DIMENSION_MM = 1
        private const val MAX_DIMENSION_MM = 20_000
    }

    private enum class PhotoTarget {
        ROOM,
        WINDOW,
        FLOOR_SPACE
    }

    private lateinit var txtRoomName:         EditText
    private lateinit var lblRoomTitle:        TextView
    private lateinit var btnSaveRoom:         Button
    private lateinit var lstWindows:          RecyclerView
    private lateinit var lstFloorSpaces:      RecyclerView
    private lateinit var btnAddWindow:        Button
    private lateinit var btnAddFloorSpace:    Button
    private lateinit var btnToggleWindows:    Button
    private lateinit var btnToggleFloor:      Button
    private lateinit var txtSearchWindows:    EditText
    private lateinit var txtSearchFloor:      EditText
    private lateinit var lblWindowCount:      TextView
    private lateinit var lblFloorSpaceCount:  TextView
    private lateinit var imgRoom:             ImageView
    private lateinit var btnTakePhoto:        Button
    private lateinit var btnPickGallery:      Button
    private lateinit var btnRemoveRoomPhoto:  Button

    private val windowList     = mutableListOf<Window>()
    private val floorSpaceList = mutableListOf<FloorSpace>()
    private val filteredWindowList = mutableListOf<Window>()
    private val filteredFloorSpaceList = mutableListOf<FloorSpace>()
    private var windowsExpanded = false
    private var floorSpacesExpanded = false
    private var windowsSearchQuery = ""
    private var floorSearchQuery = ""

    private var pendingWindowId: String? = null
    private var pendingFloorSpaceId: String? = null
    private lateinit var roomId: String
    private var pendingCameraUri: Uri? = null
    private var currentPhotoTarget: PhotoTarget = PhotoTarget.ROOM
    private var currentPhotoItemPos: Int = -1

    private lateinit var windowsAdapter: MeasurementAdapter<Window>
    private lateinit var floorAdapter: MeasurementAdapter<FloorSpace>

    // ─── Activity Result Launchers ───────────────────────────────────────────

    private val windowProductLauncher: ActivityResultLauncher<Intent> =
        registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            val selectedWindowId = pendingWindowId
            if (result.resultCode == RESULT_OK && !selectedWindowId.isNullOrBlank()) {
                val productId = result.data?.getStringExtra(RESULT_PRODUCT_ID) ?: ""
                val productName = result.data?.getStringExtra(RESULT_PRODUCT_NAME) ?: ""
                val panelCount = result.data?.getIntExtra(RESULT_PANEL_COUNT, 1) ?: 1
                val variant = result.data?.getStringExtra(RESULT_PRODUCT_VARIANT)
                if (productId.isNotBlank()) {
                    saveWindowProductById(selectedWindowId, productId, productName, panelCount, variant)
                }
            }
            pendingWindowId = null
        }

    private val floorProductLauncher: ActivityResultLauncher<Intent> =
        registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            val selectedFloorId = pendingFloorSpaceId
            if (result.resultCode == RESULT_OK && !selectedFloorId.isNullOrBlank()) {
                val productId = result.data?.getStringExtra(RESULT_PRODUCT_ID) ?: ""
                val productName = result.data?.getStringExtra(RESULT_PRODUCT_NAME) ?: ""
                val variant = result.data?.getStringExtra(RESULT_PRODUCT_VARIANT)
                if (productId.isNotBlank()) {
                    saveFloorSpaceProductById(selectedFloorId, productId, productName, variant)
                }
            }
            pendingFloorSpaceId = null
        }

    private val cameraPermissionLauncher =
        registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
            if (granted) {
                launchCameraCapture()
            } else {
                Toast.makeText(this, getString(R.string.camera_permission_denied), Toast.LENGTH_SHORT).show()
            }
        }

    private val takePictureLauncher =
        registerForActivityResult(ActivityResultContracts.TakePicture()) { success ->
            val uri = pendingCameraUri
            if (success && uri != null) {
                handleSelectedPhoto(uri)
            }
            pendingCameraUri = null
        }

    private val pickImageLauncher =
        registerForActivityResult(ActivityResultContracts.GetContent()) { uri ->
            if (uri != null) {
                handleSelectedPhoto(uri)
            }
        }

    // ─── Lifecycle ───────────────────────────────────────────────────────────

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_room_details)

        txtRoomName        = findViewById(R.id.txtRoomName)
        lblRoomTitle       = findViewById(R.id.lblRoomTitle)
        btnSaveRoom        = findViewById(R.id.btnSaveRoom)
        lstWindows         = findViewById(R.id.lstWindows)
        lstFloorSpaces     = findViewById(R.id.lstFloorSpaces)
        btnAddWindow       = findViewById(R.id.btnAddWindow)
        btnAddFloorSpace   = findViewById(R.id.btnAddFloorSpace)
        btnToggleWindows   = findViewById(R.id.btnToggleWindows)
        btnToggleFloor     = findViewById(R.id.btnToggleFloorSpaces)
        txtSearchWindows   = findViewById(R.id.txtSearchWindows)
        txtSearchFloor     = findViewById(R.id.txtSearchFloorSpaces)
        lblWindowCount     = findViewById(R.id.lblWindowCount)
        lblFloorSpaceCount = findViewById(R.id.lblFloorSpaceCount)
        imgRoom            = findViewById(R.id.imgRoom)
        btnTakePhoto       = findViewById(R.id.btnTakePhoto)
        btnPickGallery     = findViewById(R.id.btnPickGallery)
        btnRemoveRoomPhoto = findViewById(R.id.btnRemoveRoomPhoto)
        btnRemoveRoomPhoto.visibility = View.GONE

        roomId = intent.getStringExtra("room_id") ?: run { finish(); return }
        val roomName = intent.getStringExtra("room_name") ?: ""

        txtRoomName.setText(roomName)
        lblRoomTitle.text = roomName
        loadRoom(roomId)

        lstWindows.layoutManager = LinearLayoutManager(this)
        windowsAdapter = MeasurementAdapter(
            items           = filteredWindowList,
            nameFn          = { w -> w.name ?: getString(R.string.unnamed) },
            dimsFn          = { w -> getString(R.string.window_dims_format, w.widthMm, w.heightMm) },
            productFn       = { w -> formatProductDisplay(w.selectedProductName, w.selectedProductVariant) },
            photoFn         = { w -> w.photoBase64 },
            onEdit          = { pos -> openWindowEdit(pos) },
            onDelete        = { pos -> deleteWindow(pos) },
            onSelectProduct = { pos -> launchWindowProductPicker(pos) },
            onPhoto         = { pos -> startMeasurementCamera(PhotoTarget.WINDOW, pos) },
            onGallery       = { pos -> startMeasurementGallery(PhotoTarget.WINDOW, pos) },
            onRemovePhoto   = { pos -> promptRemovePhoto(PhotoTarget.WINDOW, pos) }
        )
        lstWindows.adapter = windowsAdapter

        lstFloorSpaces.layoutManager = LinearLayoutManager(this)
        floorAdapter = MeasurementAdapter(
            items           = filteredFloorSpaceList,
            nameFn          = { f -> f.name ?: getString(R.string.unnamed) },
            dimsFn          = { f -> getString(R.string.floor_dims_format, f.widthMm, f.depthMm) },
            productFn       = { f -> formatProductDisplay(f.selectedProductName, f.selectedProductVariant) },
            photoFn         = { f -> f.photoBase64 },
            onEdit          = { pos -> openFloorSpaceEdit(pos) },
            onDelete        = { pos -> deleteFloorSpace(pos) },
            onSelectProduct = { pos -> launchFloorProductPicker(pos) },
            onPhoto         = { pos -> startMeasurementCamera(PhotoTarget.FLOOR_SPACE, pos) },
            onGallery       = { pos -> startMeasurementGallery(PhotoTarget.FLOOR_SPACE, pos) },
            onRemovePhoto   = { pos -> promptRemovePhoto(PhotoTarget.FLOOR_SPACE, pos) }
        )
        lstFloorSpaces.adapter = floorAdapter

        btnToggleWindows.setOnClickListener {
            windowsExpanded = !windowsExpanded
            windowsAdapter.setExpanded(windowsExpanded)
            lstWindows.post { lstWindows.requestLayout() }
            updateToggleButtons()
        }

        btnToggleFloor.setOnClickListener {
            floorSpacesExpanded = !floorSpacesExpanded
            floorAdapter.setExpanded(floorSpacesExpanded)
            lstFloorSpaces.post { lstFloorSpaces.requestLayout() }
            updateToggleButtons()
        }

        txtSearchWindows.doAfterTextChanged {
            windowsSearchQuery = it?.toString()?.trim().orEmpty()
            applyWindowFilter()
        }

        txtSearchFloor.doAfterTextChanged {
            floorSearchQuery = it?.toString()?.trim().orEmpty()
            applyFloorFilter()
        }

        loadWindows(roomId)
        loadFloorSpaces(roomId)

        btnAddWindow.setOnClickListener     { addWindow(roomId) }
        btnAddFloorSpace.setOnClickListener { addFloorSpace(roomId) }
        btnTakePhoto.setOnClickListener {
            setPhotoTarget(PhotoTarget.ROOM)
            requestCameraPermissionAndCapture()
        }
        btnPickGallery.setOnClickListener {
            setPhotoTarget(PhotoTarget.ROOM)
            pickImageLauncher.launch("image/*")
        }
        btnRemoveRoomPhoto.setOnClickListener {
            promptRemovePhoto(PhotoTarget.ROOM, -1)
        }

        btnSaveRoom.setOnClickListener {
            val name = txtRoomName.text.toString().trim()
            if (name.isBlank()) { lblRoomTitle.text = getString(R.string.room_name_required); return@setOnClickListener }
            Firebase.firestore.collection("rooms").document(roomId)
                .update("name", name)
                .addOnSuccessListener { Log.d(FIREBASE_TAG, "Room updated"); finish() }
                .addOnFailureListener { Log.e(FIREBASE_TAG, "Error updating room", it); lblRoomTitle.text = getString(R.string.room_save_failed) }
        }
    }

    private fun loadRoom(roomId: String) {
        Firebase.firestore.collection("rooms").document(roomId).get()
            .addOnSuccessListener { doc ->
                val room = doc.toObject<Room>() ?: return@addOnSuccessListener
                txtRoomName.setText(room.name ?: "")
                lblRoomTitle.text = room.name ?: "Room"
                showRoomPhoto(room.photoBase64, room.photoUrl)
            }
            .addOnFailureListener { Log.e(FIREBASE_TAG, "Error loading room", it) }
    }

    private fun requestCameraPermissionAndCapture() {
        val granted = ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED
        if (granted) {
            launchCameraCapture()
        } else {
            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        }
    }

    private fun launchCameraCapture() {
        val uri = createTempImageUri() ?: run {
            Toast.makeText(this, getString(R.string.camera_prepare_failed), Toast.LENGTH_SHORT).show()
            return
        }
        pendingCameraUri = uri
        takePictureLauncher.launch(uri)
    }

    private fun setPhotoTarget(target: PhotoTarget, itemPos: Int = -1) {
        currentPhotoTarget = target
        currentPhotoItemPos = itemPos
    }

    private fun startMeasurementCamera(target: PhotoTarget, pos: Int) {
        setPhotoTarget(target, pos)
        requestCameraPermissionAndCapture()
    }

    private fun startMeasurementGallery(target: PhotoTarget, pos: Int) {
        setPhotoTarget(target, pos)
        pickImageLauncher.launch("image/*")
    }

    private fun handleSelectedPhoto(uri: Uri) {
        when (currentPhotoTarget) {
            PhotoTarget.ROOM -> {
                imgRoom.visibility = View.VISIBLE
                imgRoom.setImageURI(uri)
                uploadRoomPhoto(uri)
            }
            PhotoTarget.WINDOW -> saveWindowPhoto(currentPhotoItemPos, uri)
            PhotoTarget.FLOOR_SPACE -> saveFloorSpacePhoto(currentPhotoItemPos, uri)
        }
    }

    private fun createTempImageUri(): Uri? {
        return try {
            val imageDir = File(cacheDir, "room_photos").apply { mkdirs() }
            val imageFile = File.createTempFile("room_${roomId}_", ".jpg", imageDir)
            FileProvider.getUriForFile(this, "${applicationContext.packageName}.fileprovider", imageFile)
        } catch (e: Exception) {
            Log.e(FIREBASE_TAG, "Error creating temp image uri", e)
            null
        }
    }

    private fun uploadRoomPhoto(uri: Uri) {
        val base64 = encodeImageToBase64(uri)
        if (base64 == null) {
            Toast.makeText(this, getString(R.string.photo_processing_failed), Toast.LENGTH_SHORT).show()
            return
        }

        Firebase.firestore.collection("rooms").document(roomId)
            .update(mapOf("photoBase64" to base64, "photoUrl" to ""))
            .addOnSuccessListener {
                Toast.makeText(this, getString(R.string.room_photo_saved), Toast.LENGTH_SHORT).show()
                showRoomPhoto(base64, null)
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error saving photo in Firestore", it)
                val reason = it.message ?: getString(R.string.unknown_error)
                Toast.makeText(this, getString(R.string.photo_save_failed_with_reason, reason), Toast.LENGTH_LONG).show()
            }
    }

    private fun saveWindowPhoto(pos: Int, uri: Uri) {
        if (pos !in filteredWindowList.indices) return
        val base64 = encodeImageToBase64(uri) ?: run {
            Toast.makeText(this, getString(R.string.photo_processing_failed), Toast.LENGTH_SHORT).show()
            return
        }
        val window = filteredWindowList[pos]
        val windowId = window.id ?: return

        Firebase.firestore.collection("windows").document(windowId)
            .update("photoBase64", base64)
            .addOnSuccessListener {
                window.photoBase64 = base64
                applyWindowFilter()
                Toast.makeText(this, getString(R.string.window_photo_saved), Toast.LENGTH_SHORT).show()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error saving window photo", it)
                Toast.makeText(this, getString(R.string.window_photo_save_failed), Toast.LENGTH_SHORT).show()
            }
    }

    private fun saveFloorSpacePhoto(pos: Int, uri: Uri) {
        if (pos !in filteredFloorSpaceList.indices) return
        val base64 = encodeImageToBase64(uri) ?: run {
            Toast.makeText(this, getString(R.string.photo_processing_failed), Toast.LENGTH_SHORT).show()
            return
        }
        val floorSpace = filteredFloorSpaceList[pos]
        val floorSpaceId = floorSpace.id ?: return

        Firebase.firestore.collection("floorspaces").document(floorSpaceId)
            .update("photoBase64", base64)
            .addOnSuccessListener {
                floorSpace.photoBase64 = base64
                applyFloorFilter()
                Toast.makeText(this, getString(R.string.floor_photo_saved), Toast.LENGTH_SHORT).show()
            }
            .addOnFailureListener {
                Log.e(FIREBASE_TAG, "Error saving floor photo", it)
                Toast.makeText(this, getString(R.string.floor_photo_save_failed), Toast.LENGTH_SHORT).show()
            }
    }

    private fun removeMeasurementPhoto(target: PhotoTarget, pos: Int) {
        when (target) {
            PhotoTarget.ROOM -> {
                Firebase.firestore.collection("rooms").document(roomId)
                    .update(mapOf("photoBase64" to "", "photoUrl" to ""))
                    .addOnSuccessListener {
                        imgRoom.setImageDrawable(null)
                        imgRoom.visibility = View.GONE
                        btnRemoveRoomPhoto.visibility = View.GONE
                    }
                return
            }
            PhotoTarget.WINDOW -> {
                if (pos !in filteredWindowList.indices) return
                val item = filteredWindowList[pos]
                val itemId = item.id ?: return
                Firebase.firestore.collection("windows").document(itemId)
                    .update("photoBase64", "")
                    .addOnSuccessListener {
                        item.photoBase64 = null
                        applyWindowFilter()
                    }
                    .addOnFailureListener { Log.e(FIREBASE_TAG, "Error removing window photo", it) }
            }
            PhotoTarget.FLOOR_SPACE -> {
                if (pos !in filteredFloorSpaceList.indices) return
                val item = filteredFloorSpaceList[pos]
                val itemId = item.id ?: return
                Firebase.firestore.collection("floorspaces").document(itemId)
                    .update("photoBase64", "")
                    .addOnSuccessListener {
                        item.photoBase64 = null
                        applyFloorFilter()
                    }
                    .addOnFailureListener { Log.e(FIREBASE_TAG, "Error removing floor photo", it) }
